// ── 粗利計算エンジン ───────────────────────────────

// 仕入掛率から粗利率を算出（紙書籍）
const kakuToMargin = (kaku) => 1 - kaku;

// 紙書籍 粗利計算
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// SECTION 1b: 粗利計算モジュール
// calcPaperBook / calcElecBook / calcPOD / calcDigital / calcBPO
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
const calcPaperBook = (params) => {
  const pub = PUBLISHERS.find(p=>p.id===params.pubId) || PUBLISHERS[0];
  const pay = PAYMENT_METHODS.find(p=>p.id===params.paymentId) || PAYMENT_METHODS[0];
  const discRate   = params.corpDiscRate || 0;
  const netPrice   = params.listPrice * (1 - discRate);
  const revenue    = netPrice * params.qty;
  const cogs       = params.listPrice * pub.kakuRate * params.qty; // 仕入は定価ベース
  const payFee     = revenue * pay.feeRate;
  const pointCost  = params.pointUsed || 0;
  const returnProv = revenue * pub.returnRate * pub.kakuRate;
  const badDebt    = revenue * pay.badDebtRate;
  const gross      = revenue - cogs - payFee - pointCost - returnProv - badDebt;
  return {
    revenue, costOfGoods:cogs, paymentFee:payFee,
    pointCost, returnProvision:returnProv, badDebt,
    grossProfit:gross,
    grossMargin: revenue>0 ? gross/revenue : 0,
    breakdown:[
      { label:"売上（税抜）",     amount:revenue,    type:"revenue" },
      { label:"仕入原価",         amount:-cogs,      type:"cost"    },
      { label:"決済手数料",       amount:-payFee,    type:"cost"    },
      { label:"ポイント原価",     amount:-pointCost, type:"cost"    },
      { label:"返品引当",         amount:-returnProv,type:"risk"    },
      { label:"貸倒引当",         amount:-badDebt,   type:"risk"    },
    ],
  };
};

// 電子書籍 粗利計算
const calcElecBook = (params) => {
  const pub     = PUBLISHERS.find(p=>p.id===params.pubId) || PUBLISHERS[0];
  const pay     = PAYMENT_METHODS.find(p=>p.id===params.paymentId) || PAYMENT_METHODS[0];
  const revenue = params.salePrice * params.qty;
  const cogs    = revenue * pub.elecShareRate; // レベニューシェア（出版社取り分）
  const payFee  = revenue * pay.feeRate;
  const gross   = revenue - cogs - payFee;
  return {
    revenue, costOfGoods:cogs, paymentFee:payFee,
    pointCost:0, returnProvision:0, badDebt:0,
    grossProfit:gross,
    grossMargin: revenue>0 ? gross/revenue : 0,
    breakdown:[
      { label:"売上（税抜）",         amount:revenue, type:"revenue" },
      { label:`出版社レベニューシェア（${Math.round(pub.elecShareRate*100)}%）`, amount:-cogs, type:"cost" },
      { label:"決済手数料",           amount:-payFee, type:"cost"   },
    ],
  };
};

// POD書籍 粗利計算
const calcPOD = (params) => {
  const pay      = PAYMENT_METHODS.find(p=>p.id===params.paymentId) || PAYMENT_METHODS[0];
  const revenue  = params.listPrice * params.qty;
  const printCost= params.printCostPerUnit * params.qty;
  const payFee   = revenue * pay.feeRate;
  const gross    = revenue - printCost - payFee;
  return {
    revenue, costOfGoods:0, paymentFee:payFee,
    pointCost:0, returnProvision:0, badDebt:0,
    printCost,
    grossProfit:gross,
    grossMargin: revenue>0 ? gross/revenue : 0,
    breakdown:[
      { label:"売上（税抜）",   amount:revenue,    type:"revenue" },
      { label:"印刷費（都度）", amount:-printCost, type:"cost"    },
      { label:"決済手数料",     amount:-payFee,    type:"cost"    },
    ],
  };
};

// デジタル商品・SaaS 粗利計算（原価≒0）
const calcDigital = (params) => {
  const pay       = PAYMENT_METHODS.find(p=>p.id===params.paymentId) || PAYMENT_METHODS[0];
  const revenue   = params.salePrice * params.qty;
  const payFee    = revenue * pay.feeRate;
  const infra     = (params.infraCostPer || 0) * params.qty;
  const gross     = revenue - payFee - infra;
  return {
    revenue, costOfGoods:infra, paymentFee:payFee,
    pointCost:0, returnProvision:0, badDebt:0,
    grossProfit:gross,
    grossMargin: revenue>0 ? gross/revenue : 0,
    breakdown:[
      { label:"売上（税抜）",   amount:revenue, type:"revenue" },
      { label:"インフラ費按分", amount:-infra,  type:"cost"    },
      { label:"決済手数料",     amount:-payFee, type:"cost"    },
    ],
  };
};

// BPO案件 粗利計算（工数ベース）
const calcBPO = (params) => {
  const revenue   = params.billing;
  const laborCost = params.manHours * params.laborCostPerHour;
  const gross     = revenue - laborCost;
  return {
    revenue, costOfGoods:0, paymentFee:0,
    pointCost:0, returnProvision:0, badDebt:0,
    laborCost,
    grossProfit:gross,
    grossMargin: revenue>0 ? gross/revenue : 0,
    breakdown:[
      { label:"請求額",   amount:revenue,    type:"revenue" },
      { label:"人件費原価（工数×単価）", amount:-laborCost, type:"cost" },
    ],
  };
};


