function checkSameDayDelivery(zip) {
  const cleanZip = (zip||"").replace(/[^0-9-]/g,"");
  const zoneName = SAME_DAY_ZONES[cleanZip];
  return { possible: !!zoneName, zone: zoneName||null };
}

