const StoreView = ({ onToast, darkMode }) => {
  var T = darkMode ? T_DARK : T_LIGHT;
  const [tab,       setTab]       = useState("overview");
  const [storeId,   setStoreId]   = useState("s1");
  const [dateIdx,   setDateIdx]   = useState(0);   // 0 = 最新日
  const [showRoadmap, setShowRoadmap] = useState(false);

  const store    = STORES_LIST.find(s => s.id === storeId);
  const storeDay = (POS_DAILY[storeId]||[])[dateIdx] || (POS_DAILY[storeId]||[])[0];
  const dateList = (POS_DAILY["s1"]||[]).map(d => d.date);

  // 全店合計（選択日）
  const allTotal = STORES_LIST.reduce((acc, s) => {
    const d = (POS_DAILY[s.id]||[])[dateIdx];
    if (!d) return acc;
    return {
      visitors:    acc.visitors    + d.visitors,
      trans:       acc.trans       + d.trans,
      sales:       acc.sales       + d.sales,
      gross:       acc.gross       + d.gross,
    };
  }, { visitors:0, trans:0, sales:0, gross:0 });

  const hourly = HOURLY_VISITORS[storeId] || [];
  const peakH  = hourly.indexOf(Math.max(...hourly));
  const barMax = Math.max(...hourly, 1);
  const fmtM   = (v) => `¥${(v/10000).toFixed(0)}万`;

  return (
    <div>
      <SectionHeader title="店舗管理（POS）"
        desc="来店者数・売上・在庫を店舗ごとにリアルタイム把握"
        action={
          <div style={{ display:"flex", gap:8 }}>
            <Btn variant="ghost" small onClick={() => setShowRoadmap(true)}>📱 AIタブレット化</Btn>
            <Btn variant="ghost" small onClick={() => onToast("POSデータCSVを出力しました")}>📤 CSV出力</Btn>
          </div>
        } />

      {/* 日付ピッカー */}
      <div style={{ display:"flex", gap:8, marginBottom:14, alignItems:"center", flexWrap:"wrap" }}>
        <span style={{ fontSize:12, color:T.ink4, fontWeight:700, flexShrink:0 }}>📅 集計日：</span>
        {dateList.map((d, i) => (
          <button key={d} onClick={() => setDateIdx(i)}
            style={{ padding:"4px 11px", borderRadius:6, fontSize:11, cursor:"pointer",
              fontFamily:"inherit",
              border:`1.5px solid ${dateIdx===i ? T.g2 : T.rule}`,
              background: dateIdx===i ? T.okPale : T.white,
              color: dateIdx===i ? T.g2 : T.ink4,
              fontWeight: dateIdx===i ? 700 : 400 }}>
            {d.slice(5)}
          </button>
        ))}
      </div>

      {/* 全店KPIバー */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:10, marginBottom:14 }}>
        {[
          { label:"全店 来店者",  val:`${allTotal.visitors}人`,               icon:"👥", color:T.g2    },
          { label:"全店 購入者",  val:`${allTotal.trans}件`,                   icon:"🛒", color:T.navy  },
          { label:"全店 売上",    val:fmtM(allTotal.sales),                    icon:"💹", color:T.g2    },
          { label:"全店 粗利",    val:fmtM(allTotal.gross),                    icon:"🧮", color:T.ok    },
        ].map((s, i) => (
          <div key={i} style={{ padding:"14px 16px", background:T.bg,
            borderRadius:8, border:`1px solid ${s.color}20` }}>
            <div style={{ fontSize:16, marginBottom:4 }}>{s.icon}</div>
            <div style={{ fontFamily:"'Inter'", fontSize:20, fontWeight:800, color:s.color }}>{s.val}</div>
            <div style={{ fontSize:11, color:s.color, fontWeight:700, marginTop:2 }}>{s.label}</div>
          </div>
        ))}
      </div>

      <Tabs tabs={[
        { id:"overview",  icon:"📊", label:"全店比較" },
        { id:"detail",    icon:"🏪", label:"店舗詳細" },
        { id:"inventory", icon:"📦", label:"店舗別在庫" },
        { id:"hourly",    icon:"⏰", label:"時間帯分析" },
      ]} active={tab} onChange={setTab} />

      {/* ══ 全店比較 ══ */}
      {tab === "overview" && (
        <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
          {STORES_LIST.map(s => {
            const d = (POS_DAILY[s.id]||[])[dateIdx];
            if (!d) return null;
            const cvr = Math.round(d.trans / Math.max(d.visitors,1) * 100);
            const grossRate = Math.round(d.gross / Math.max(d.sales,1) * 100);
            const maxSales = Math.max(...STORES_LIST.map(st => (POS_DAILY[st.id]||[])[dateIdx]?.sales||0), 1);
            return (
              <div key={s.id}
                onClick={() => { setStoreId(s.id); setTab("detail"); }}
                style={{ background:T.white, borderRadius:12, padding:"16px 20px",
                  border:`2px solid ${storeId===s.id ? s.color : T.rule}`,
                  boxShadow:T.sS, cursor:"pointer" }}>
                <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                  <div style={{ width:44, height:44, borderRadius:10, background:s.color,
                    display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                    <span style={{ fontSize:22 }}>🏪</span>
                  </div>
                  <div style={{ flex:1 }}>
                    <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:8 }}>
                      <span style={{ fontSize:14, fontWeight:800, color:T.ink }}>{s.name}</span>
                      {s.tabletReady && (
                        <span style={{ fontSize:10, padding:"2px 6px", borderRadius:4,
                          background:T.okPale, color:T.ok, fontWeight:700 }}>📱 タブレット対応</span>
                      )}
                      <span style={{ fontSize:10, color:T.ink4, marginLeft:"auto" }}>
                        スタッフ{s.staff}名 / {s.openH}:00〜{s.closeH}:00
                      </span>
                    </div>
                    <div style={{ display:"grid", gridTemplateColumns:"repeat(5,1fr)", gap:8, marginBottom:8 }}>
                      {[
                        { label:"来店者", val:`${d.visitors}人`,   color:T.g2   },
                        { label:"購入者", val:`${d.trans}件`,      color:T.navy },
                        { label:"CVR",    val:`${cvr}%`,           color:cvr>=50?T.ok:T.amber },
                        { label:"売上",   val:fmtM(d.sales),       color:T.g2   },
                        { label:"粗利率", val:`${grossRate}%`,     color:grossRate>=35?T.ok:T.amber },
                      ].map((k, i) => (
                        <div key={i} style={{ padding:"8px 10px", background:T.bg,
                          borderRadius:7, border:`1px solid ${T.rule}`, textAlign:"center" }}>
                          <div style={{ fontFamily:"'Inter'", fontSize:14, fontWeight:800, color:k.color }}>{k.val}</div>
                          <div style={{ fontSize:10, color:T.ink4, marginTop:1 }}>{k.label}</div>
                        </div>
                      ))}
                    </div>
                    {/* 売上バー */}
                    <div style={{ height:5, background:T.rule, borderRadius:5, overflow:"hidden" }}>
                      <div style={{ height:"100%", borderRadius:5, background:s.color,
                        width:`${Math.round(d.sales/maxSales*100)}%`, transition:"width .4s" }} />
                    </div>
                    <div style={{ fontSize:10, color:T.ink4, marginTop:3 }}>
                      本日ベスト：📚 {d.topBook}
                    </div>
                  </div>
                  <span style={{ fontSize:11, color:T.ink4, flexShrink:0 }}>詳細 →</span>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* ══ 店舗詳細 ══ */}
      {tab === "detail" && (
        <div>
          <div style={{ display:"flex", gap:8, marginBottom:14 }}>
            {STORES_LIST.map(s => (
              <button key={s.id} onClick={() => setStoreId(s.id)}
                style={{ padding:"8px 18px", borderRadius:8, fontSize:12, cursor:"pointer",
                  fontFamily:"inherit",
                  border:`2px solid ${storeId===s.id ? s.color : T.rule}`,
                  background: storeId===s.id ? `${s.color}12` : T.white,
                  color: storeId===s.id ? s.color : T.ink4,
                  fontWeight: storeId===s.id ? 800 : 400 }}>
                🏪 {s.name}
              </button>
            ))}
          </div>

          {storeDay && (
            <>
              <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:10, marginBottom:14 }}>
                {[
                  { label:"来店者数", val:`${storeDay.visitors}人`,  icon:"👥", color:store.color },
                  { label:"購入件数", val:`${storeDay.trans}件`,     icon:"🛒", color:T.navy      },
                  { label:"客単価",   val:`¥${Math.round(storeDay.sales/Math.max(storeDay.trans,1)).toLocaleString()}`, icon:"💴", color:T.g2 },
                  { label:"日次粗利", val:fmtM(storeDay.gross),      icon:"🧮", color:T.ok        },
                ].map((k, i) => (
                  <div key={i} style={{ padding:"14px 16px", background:T.white,
                    borderRadius:8, borderLeft:`4px solid ${k.color}`,
                    border:`1.5px solid ${k.color}25`, borderLeftWidth:4 }}>
                    <div style={{ fontSize:16, marginBottom:4 }}>{k.icon}</div>
                    <div style={{ fontFamily:"'Inter'", fontSize:22, fontWeight:800, color:k.color }}>{k.val}</div>
                    <div style={{ fontSize:11, color:T.ink4, marginTop:2 }}>{k.label}</div>
                  </div>
                ))}
              </div>

              {/* 7日間バーチャート */}
              <Card style={{ padding:"16px 20px", marginBottom:12 }}>
                <div style={{ fontSize:13, fontWeight:800, color:T.ink, marginBottom:12 }}>
                  📈 7日間 売上推移 — {store.name}
                </div>
                <div style={{ display:"flex", gap:6, alignItems:"flex-end", height:100 }}>
                  {(POS_DAILY[storeId]||[]).slice().reverse().map((d, i) => {
                    const maxS = Math.max(...(POS_DAILY[storeId]||[]).map(x=>x.sales), 1);
                    const h = Math.max(6, Math.round(d.sales/maxS*80));
                    const isSel = i === (6 - dateIdx);
                    return (
                      <div key={d.date} onClick={() => setDateIdx(6-i)}
                        style={{ flex:1, display:"flex", flexDirection:"column",
                          alignItems:"center", gap:3, cursor:"pointer" }}>
                        <div style={{ fontSize:10, color:T.ink4, fontWeight:700 }}>
                          {fmtM(d.sales)}
                        </div>
                        <div style={{ width:"100%", height:h, borderRadius:"4px 4px 0 0",
                          background: isSel ? store.color : `${store.color}50`,
                          border: isSel ? `2px solid ${store.color}` : "none",
                          transition:"height .3s" }} />
                        <div style={{ fontSize:10,
                          color: isSel ? store.color : T.ink4,
                          fontWeight: isSel ? 800 : 400 }}>
                          {d.date.slice(5)}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </Card>

              {/* 店舗情報 */}
              <Card style={{ padding:"16px 20px" }}>
                <div style={{ fontSize:13, fontWeight:800, color:T.ink, marginBottom:10 }}>🏪 店舗情報</div>
                <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:8 }}>
                  {[
                    { label:"エリア",      val:store.area },
                    { label:"POSシステム", val:store.posType },
                    { label:"営業時間",    val:`${store.openH}:00〜${store.closeH}:00` },
                    { label:"スタッフ数",  val:`${store.staff}名` },
                    { label:"タブレット",  val:store.tabletReady ? "✅ 対応済" : "❌ 未対応" },
                    { label:"本日ベスト",  val:storeDay.topBook },
                  ].map((r, i) => (
                    <div key={i} style={{ padding:"10px 12px", background:T.bg,
                      borderRadius:7, border:`1px solid ${T.rule}` }}>
                      <div style={{ fontSize:10, color:T.ink4, marginBottom:2 }}>{r.label}</div>
                      <div style={{ fontSize:12, fontWeight:700, color:T.ink,
                        overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                        {r.val}
                      </div>
                    </div>
                  ))}
                </div>
                {!store.tabletReady && (
                  <div style={{ marginTop:10, padding:"8px 12px", background:T.amberPale,
                    borderRadius:7, border:`1px solid ${T.amber}25`,
                    fontSize:11, color:T.ink3 }}>
                    📱 AIタブレット未導入。
                    <button onClick={() => setShowRoadmap(true)}
                      style={{ background:"none", border:"none", color:T.navy,
                        cursor:"pointer", fontWeight:700, fontSize:11, padding:"0 4px" }}>
                      ロードマップを確認 →
                    </button>
                  </div>
                )}
              </Card>
            </>
          )}
        </div>
      )}

      {/* ══ 店舗別在庫 ══ */}
      {tab === "inventory" && (
        <div>
          <div style={{ padding:"8px 14px", background:T.navyPale, borderRadius:8,
            border:`1px solid ${T.navy}20`, marginBottom:12,
            fontSize:12, color:T.navy, fontWeight:700 }}>
            📦 各店舗の棚在庫（EC倉庫とは別管理）
          </div>
          <table style={{ width:"100%", borderCollapse:"collapse", fontSize:12 }}>
            <thead>
              <tr style={{ background:T.g1, color:"#fff" }}>
                <th style={{ padding:"9px 12px", textAlign:"left", fontWeight:700 }}>書籍名</th>
                {STORES_LIST.map(s => (
                  <th key={s.id} style={{ padding:"9px 12px", textAlign:"center", fontWeight:700 }}>{s.name}</th>
                ))}
                <th style={{ padding:"9px 12px", textAlign:"center", fontWeight:700 }}>合計</th>
              </tr>
            </thead>
            <tbody>
              {Object.entries(STORE_INVENTORY).map(([title, inv], i) => {
                const total = Object.values(inv).reduce((s, v) => s + v, 0);
                return (
                  <tr key={title} style={{ background:i%2===0?T.white:T.bg,
                    borderBottom:`1px solid ${T.rule}` }}>
                    <td style={{ padding:"9px 12px", fontSize:12, fontWeight:700, color:T.ink,
                      maxWidth:220, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                      {title}
                    </td>
                    {STORES_LIST.map(s => {
                      const qty = (inv)[s.id] || 0;
                      return (
                        <td key={s.id} style={{ padding:"9px 12px", textAlign:"center" }}>
                          <span style={{ fontFamily:"'Inter'", fontSize:13, fontWeight:700,
                            color: qty===0 ? T.red : qty<10 ? T.amber : T.ok }}>
                            {qty===0 ? "なし" : `${qty}冊`}
                          </span>
                        </td>
                      );
                    })}
                    <td style={{ padding:"9px 12px", textAlign:"center",
                      fontFamily:"'Inter'", fontSize:13, fontWeight:800,
                      color: total===0 ? T.red : T.ink }}>
                      {total}冊
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          <div style={{ marginTop:10, padding:"10px 14px", background:T.amberPale,
            borderRadius:8, border:`1px solid ${T.amber}30`, fontSize:11, color:T.ink3 }}>
            ⚠ 在庫数はPOS連携による推計値です。週次で実地棚卸しを推奨します。
          </div>
        </div>
      )}

      {/* ══ 時間帯分析 ══ */}
      {tab === "hourly" && (
        <div>
          <div style={{ display:"flex", gap:8, marginBottom:14 }}>
            {STORES_LIST.map(s => (
              <button key={s.id} onClick={() => setStoreId(s.id)}
                style={{ padding:"6px 14px", borderRadius:7, fontSize:12, cursor:"pointer",
                  fontFamily:"inherit",
                  border:`2px solid ${storeId===s.id ? s.color : T.rule}`,
                  background: storeId===s.id ? `${s.color}12` : T.white,
                  color: storeId===s.id ? s.color : T.ink4,
                  fontWeight: storeId===s.id ? 700 : 400 }}>
                {s.name}
              </button>
            ))}
          </div>
          <Card style={{ padding:"18px 20px" }}>
            <div style={{ fontSize:13, fontWeight:800, color:T.ink, marginBottom:4 }}>
              ⏰ 時間帯別 来客数 — {store.name}（本日）
            </div>
            <div style={{ fontSize:11, color:T.ink4, marginBottom:16 }}>
              ピーク：{peakH}時〜{peakH+1}時（{hourly[peakH]}人）
            </div>
            <div style={{ display:"flex", gap:3, alignItems:"flex-end", height:110, paddingBottom:20, position:"relative" }}>
              {hourly.map((v, h) => {
                const barH = v > 0 ? Math.max(4, Math.round(v/barMax*86)) : 0;
                const isOpen = h >= store.openH && h < store.closeH;
                const isPeak = v === barMax && v > 0;
                return (
                  <div key={h} style={{ flex:1, display:"flex", flexDirection:"column",
                    alignItems:"center", justifyContent:"flex-end", height:110, gap:2 }}>
                    {isPeak && (
                      <div style={{ fontSize:10, color:store.color, fontWeight:800 }}>▲{v}</div>
                    )}
                    <div style={{ width:"100%", height:barH,
                      borderRadius:"3px 3px 0 0",
                      background: isPeak ? store.color : isOpen ? `${store.color}65` : T.rule,
                      transition:"height .3s" }} />
                    {h % 3 === 0 && (
                      <div style={{ fontSize:10, color:T.ink4, position:"absolute", bottom:0 }}>
                        {h}h
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
            <div style={{ display:"flex", gap:12, fontSize:10, color:T.ink4, marginTop:4 }}>
              <span style={{ display:"flex", alignItems:"center", gap:4 }}>
                <div style={{ width:10, height:10, background:store.color, borderRadius:2 }} />ピーク
              </span>
              <span style={{ display:"flex", alignItems:"center", gap:4 }}>
                <div style={{ width:10, height:10, background:`${store.color}65`, borderRadius:2 }} />営業時間内
              </span>
            </div>
          </Card>
          <AIInsight type="action"
            text={`${store.name}のピーク（${peakH}時台）にスタッフを1名追加すると購買転換率が約+8%改善の見込み。霞が関店はタブレットPOS導入済みのため、時間帯データのリアルタイム取得が既に可能です。`} />
        </div>
      )}

      {/* AIタブレット化ロードマップ モーダル */}
      {showRoadmap && (
        <div onClick={() => setShowRoadmap(false)}
          style={{ position:"fixed", inset:0, background:"rgba(15,51,32,.55)", zIndex:1100,
            display:"flex", alignItems:"center", justifyContent:"center", padding:20 }}>
          <div onClick={e => e.stopPropagation()}
            style={{ background:T.white, borderRadius:14, width:620, maxHeight:"90vh",
              overflowY:"auto", boxShadow:"0 8px 48px rgba(0,0,0,.22)" }}>
            <div style={{ padding:"16px 22px", borderBottom:`1px solid ${T.rule}`,
              display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <div style={{ fontSize:15, fontWeight:800, color:T.ink }}>📱 AIタブレット化 ロードマップ</div>
              <button onClick={() => setShowRoadmap(false)}
                style={{ background:T.bg, border:`1px solid ${T.rule}`,
                  borderRadius:6, padding:"4px 10px", cursor:"pointer", color:T.ink4, fontSize:12 }} aria-label="閉じる">✕</button>
            </div>
            <div style={{ padding:"20px 22px" }}>
              {[
                { phase:"Phase 1（〜3ヶ月）", color:T.ok, icon:"🖥", items:[
                  "iPad + Square / Airレジ 導入（月額〜¥3,300〜）",
                  "バーコードスキャンで書籍情報を自動取得",
                  "POSデータをCSV or APIでこの管理画面に自動連携",
                  "在庫リアルタイム更新（EC在庫と連動）",
                ]},
                { phase:"Phase 2（3〜6ヶ月）", color:T.amber, icon:"🤖", items:[
                  "AI書籍レコメンド：来店者の購入履歴から接客提案",
                  "会員証スキャン → 購入履歴・ポイント即時確認",
                  "タブレットカメラで棚在庫を自動カウント（画像認識）",
                  "来客予測AI：曜日×天気×法改正イベントで翌日来客数予測",
                ]},
                { phase:"Phase 3（6ヶ月〜）", color:T.navy, icon:"🚀", items:[
                  "全店データをリアルタイム統合（本管理画面に自動反映）",
                  "在庫閾値を下回ると自動発注を提案",
                  "スタッフシフト最適化（来客予測×稼働コスト）",
                  "セルフレジ対応：QRコード決済・会員ポイント自動付与",
                ]},
              ].map((ph, i) => (
                <div key={i} style={{ marginBottom:18 }}>
                  <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:8 }}>
                    <span style={{ fontSize:18 }}>{ph.icon}</span>
                    <span style={{ padding:"3px 12px", borderRadius:6, fontWeight:800, fontSize:12,
                      background:`${ph.color}18`, color:ph.color }}>
                      {ph.phase}
                    </span>
                  </div>
                  {ph.items.map((item, j) => (
                    <div key={j} style={{ padding:"7px 12px",
                      borderLeft:`3px solid ${ph.color}`, marginBottom:4,
                      background:`${ph.color}08`, borderRadius:"0 7px 7px 0",
                      fontSize:12, color:T.ink3 }}>
                      • {item}
                    </div>
                  ))}
                </div>
              ))}
              <div style={{ padding:"12px 16px", background:T.goldPale, borderRadius:8,
                border:`1px solid ${T.gold}30`, fontSize:12, color:T.ink3, lineHeight:1.6 }}>
                💡 <strong>推奨：</strong>霞が関店（iPad POS導入済）でAPI連携を先行試験し、
                効果検証後に本店・丸の内店へ展開するのが最もリスクが低いです。
                まずはCSV連携（Phase 1）から着手できます。
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

