const Table = ({ cols, rows, onRow, expandedId, renderExpanded, expandAll }) => (
  <div style={{ overflowX:"auto" }}>
    <table style={{ width:"100%", borderCollapse:"collapse", fontSize:14 }}>
      <thead>
        <tr style={{ borderBottom:`2px solid ${T.rule}` }}>
          {cols.map((c,i)=>(
            <th key={i} style={{ padding:"11px 14px", textAlign:"left", fontSize:12,
              fontWeight:700, color:T.ink4, letterSpacing:".06em",
              whiteSpace:"nowrap", background:T.surface }}>{c.label}</th>
          ))}
        </tr>
      </thead>
      <tbody>
        {rows.map((row,ri)=>{
          const isExpanded = expandAll || (expandedId && expandedId === (row.id||ri));
          return (
            <React.Fragment key={row.id||ri}>
              <tr onClick={()=>onRow&&onRow(row)}
                style={{ borderBottom: isExpanded?"none":`1px solid ${T.rule}`,
                  cursor:onRow?"pointer":"default",
                  background:isExpanded?"rgba(26,92,56,.04)":"" }}
                onMouseEnter={e=>{ if(onRow)e.currentTarget.style.background="rgba(26,92,56,.04)"; }}
                onMouseLeave={e=>{ if(!isExpanded)e.currentTarget.style.background=""; }}>
                {cols.map((c,ci)=>(
                  <td key={ci} style={{ padding:"12px 14px", verticalAlign:"middle",
                    whiteSpace:c.wrap?"normal":"nowrap", maxWidth:c.maxW||"none" }}>
                    {c.render?c.render(row):row[c.key]}
                  </td>
                ))}
              </tr>
              {isExpanded && renderExpanded && (
                <tr>
                  <td colSpan={cols.length}
                    style={{ padding:0, background:"rgba(26,92,56,.03)",
                      borderBottom:`1px solid ${T.rule}` }}>
                    {renderExpanded(row)}
                  </td>
                </tr>
              )}
            </React.Fragment>
          );
        })}
      </tbody>
    </table>
  </div>
);

const Progress = ({ value, max, color=T.g2, h=6, showPct=false }) => (
  <div style={{ display:"flex", alignItems:"center", gap:8 }}>
    <div style={{ flex:1, height:h, background:T.rule, borderRadius:h, overflow:"hidden" }}>
      <div style={{ height:"100%", borderRadius:h, background:color,
        width:`${Math.min(100,Math.round(value/max*100))}%`, transition:"width .4s" }} />
    </div>
    {showPct && <span style={{ fontSize:11, color:T.ink4, fontFamily:"'Inter'", minWidth:30 }}>
      {Math.round(value/max*100)}%
    </span>}
  </div>
);

const Tabs = ({ tabs, active, onChange }) => (
  <div style={{ display:"flex", borderBottom:`1px solid ${T.rule}`,
    background:T.surface, marginBottom:20, overflowX:"auto" }}>
    {tabs.map(t=>(
      <button key={t.id} onClick={()=>onChange(t.id)} style={{
        padding:"12px 22px", background:"none", border:"none", cursor:"pointer",
        fontSize:14, fontWeight:active===t.id?700:400,
        color:active===t.id?T.g2:T.ink4,
        borderBottom:`2px solid ${active===t.id?T.g2:"transparent"}`,
        whiteSpace:"nowrap", marginBottom:-1, transition:"all .15s" }}>
        {t.icon && <span style={{marginRight:6}}>{t.icon}</span>}{t.label}
        {t.badge && <span style={{ marginLeft:6, fontSize:11, fontWeight:700,
          background:T.red, color:"#fff", padding:"1px 6px", borderRadius:8 }}>{t.badge}</span>}
      </button>
    ))}
  </div>
);

// ── AI分析インサイトコンポーネント ──────────
const AIInsight = ({ insights, defaultOpen=false }) => {
  const [open, setOpen] = useState(defaultOpen);
  if (!insights || insights.length === 0) return null;
  const STYLES = {
    summary:  { icon:"📋", color:T.navy,   bg:T.navyPale,   label:"概要" },
    positive: { icon:"✅", color:T.ok,     bg:T.okPale,     label:"好材料" },
    warning:  { icon:"⚠", color:T.amber,  bg:T.amberPale,  label:"注意点" },
    action:   { icon:"💡", color:T.purple,  bg:T.purplePale, label:"改善提案" },
    risk:     { icon:"🔴", color:T.red,    bg:T.redPale,    label:"リスク" },
  };
  const InsightRow = ({ ins }) => {
    const s = STYLES[ins.type] || STYLES.summary;
    return (
      <div style={{ display:"flex", gap:10, padding:"11px 14px",
        borderRadius:8, background:s.bg, border:`1px solid ${s.color}20` }}>
        <span style={{ fontSize:16, flexShrink:0 }}>{s.icon}</span>
        <div>
          <div style={{ fontSize:12, fontWeight:800, color:s.color,
            letterSpacing:".06em", marginBottom:3 }}>{s.label}</div>
          <div style={{ fontSize:13, color:T.ink2, lineHeight:1.8 }}>{ins.text}</div>
        </div>
      </div>
    );
  };
  // 概要タイプのみ常時表示、それ以外は開閉制御
  const summaries = insights.filter(i => i.type === "summary");
  const others    = insights.filter(i => i.type !== "summary");
  return (
    <div style={{ marginBottom:16, borderRadius:10,
      border:`1.5px solid rgba(106,27,154,.25)`,
      background:"linear-gradient(135deg,rgba(106,27,154,.04),rgba(34,184,122,.04))",
      overflow:"hidden" }}>
      {/* ヘッダー＋概要（常時表示） */}
      <div style={{ padding:"13px 18px 0", display:"flex", alignItems:"flex-start", gap:10 }}>
        <span style={{ fontSize:18, marginTop:2 }}>🤖</span>
        <div style={{ flex:1 }}>
          <div style={{ fontSize:14, fontWeight:800, color:T.purple, marginBottom:summaries.length?10:0 }}>
            AI分析インサイト
          </div>
          {summaries.map((ins,i) => <div key={i} style={{ marginBottom:8 }}><InsightRow ins={ins} /></div>)}
        </div>
      </div>
      {/* 開閉ボタン（概要以外がある場合のみ表示） */}
      {others.length > 0 && (
        <>
          <button onClick={()=>setOpen(!open)}
            style={{ width:"100%", padding:"8px 18px 10px", background:"none", border:"none",
              cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center",
              gap:6, color:T.purple, fontSize:12, fontWeight:700 }}>
            {open ? "▲ 閉じる" : `▼ 詳細を見る（好材料・注意点・改善提案 計${others.length}件）`}
          </button>
          {open && (
            <div style={{ padding:"0 18px 14px", display:"flex", flexDirection:"column", gap:8 }}>
              {others.map((ins, i) => <InsightRow key={i} ins={ins} />)}
            </div>
          )}
        </>
      )}
      {others.length === 0 && <div style={{ height:14 }} />}
    </div>
  );
};

