// SECTION 9: View: レポート
// ReportsView：月次・年次レポート PDF出力
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
const ReportsView = ({ onToast, onNav, darkMode }) => {
  var T = darkMode ? T_DARK : T_LIGHT;
  const [active, setActive] = useState(null);

  const categories = [...new Set(REPORT_DEFS.map(r=>r.category))];

  if (active) {
    const rep = REPORT_DEFS.find(r=>r.id===active);
    return (
      <div>
        <SectionHeader
          title={rep.title}
          desc={rep.desc}
          action={
            <div style={{ display:"flex", gap:8 }}>
              <Btn variant="ghost" small onClick={()=>setActive(null)}>← 一覧に戻る</Btn>
              <Btn variant="ghost" small icon="📊" onClick={()=>onToast("Excel出力")}>Excel</Btn>
              <Btn icon="📄" onClick={()=>onToast(`「${rep.title}」PDF出力（Puppeteer）`)}>PDF出力</Btn>
            </div>
          } />

        <AIInsight defaultOpen={true} insights={[rep.insight]} />

        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:16 }}>
          {/* セクション構成 */}
          <Card style={{ padding:"20px 24px" }}>
            <h3 style={{ fontSize:14, fontWeight:700, color:T.ink, marginBottom:16 }}>
              📋 レポート構成セクション
            </h3>
            {rep.sections.map((s,i)=>(
              <div key={i} style={{ display:"flex", gap:12, alignItems:"center",
                padding:"11px 14px", background:T.bg, borderRadius:6,
                border:`1px solid ${T.rule}`, marginBottom:8 }}>
                <div style={{ width:24, height:24, borderRadius:"50%",
                  background:`linear-gradient(135deg,${T.g2},${T.g3})`,
                  color:"#fff", fontSize:11, fontWeight:800,
                  display:"flex", alignItems:"center", justifyContent:"center",
                  flexShrink:0 }}>{i+1}</div>
                <span style={{ fontSize:13, color:T.ink2 }}>{s}</span>
              </div>
            ))}
          </Card>

          {/* 出力設定 */}
          <div style={{ display:"flex", flexDirection:"column", gap:12 }}>
            <Card style={{ padding:"20px 24px" }}>
              <h3 style={{ fontSize:14, fontWeight:700, color:T.ink, marginBottom:16 }}>⚙ 出力設定</h3>
              {[
                { label:"期間",       value:"2026年3月（今月）",       edit:true  },
                { label:"比較軸",     value:"前年同月比",              edit:true  },
                { label:"出力形式",   value:"PDF + Excel（同梱）",     edit:true  },
                { label:"宛先",       value:"社内用（ロゴ入り）",       edit:true  },
                { label:"最終生成日", value:"2026-03-10 15:00",        edit:false },
              ].map((s,i)=>(
                <div key={i} style={{ display:"flex", justifyContent:"space-between",
                  alignItems:"center", padding:"9px 0",
                  borderBottom:i<4?`1px solid ${T.rule}`:"none" }}>
                  <span style={{ fontSize:13, color:T.ink4 }}>{s.label}</span>
                  <div style={{ display:"flex", gap:8, alignItems:"center" }}>
                    <span style={{ fontSize:13, fontWeight:700, color:T.ink2 }}>{s.value}</span>
                    {s.edit && <button style={{ fontSize:11, background:"none",
                      border:`1px solid ${T.rule}`, borderRadius:4, padding:"2px 8px",
                      cursor:"pointer", color:T.ink4 }}>変更</button>}
                  </div>
                </div>
              ))}
            </Card>

            <Card style={{ padding:"20px 24px" }}>
              <h3 style={{ fontSize:14, fontWeight:700, color:T.ink, marginBottom:14 }}>🔗 関連データへ移動</h3>
              {[
                { label:"売上管理 →",     nav:"sales"      },
                { label:"書籍管理 →",     nav:"books"      },
                { label:"会員管理 →",     nav:"members"    },
                { label:"出版社レポート →",nav:"pub_report" },
              ].slice(0,3).map((l,i)=>(
                <button key={i} onClick={()=>onNav(l.nav)}
                  style={{ display:"block", width:"100%", textAlign:"left",
                    padding:"9px 12px", borderRadius:6, marginBottom:6,
                    background:T.bg, border:`1px solid ${T.rule}`,
                    cursor:"pointer", fontSize:13, color:T.g2, fontWeight:700 }}>
                  {l.label}
                </button>
              ))}
            </Card>

            <div style={{ display:"flex", gap:10 }}>
              <Btn style={{ flex:1 }} onClick={()=>onToast(`「${rep.title}」を生成中...`)}>
                📄 今すぐ生成
              </Btn>
              <Btn variant="secondary" onClick={()=>onToast("月次自動生成をスケジュール設定")}>
                🗓 自動生成設定
              </Btn>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div>
      <SectionHeader title="レポート"
        desc="売上・顧客・コンテンツ・書籍・BPO・出版社向けレポートをワンクリックで生成"
        action={<Btn variant="ghost" icon="⚙" onClick={()=>onToast("レポート自動送信設定")}>自動送信設定</Btn>} />

      <AIInsight defaultOpen={true} insights={[
        { type:"action", text:"今月優先生成すべきレポートは「出版社別提出レポート（弘文堂）」です。電子化リクエスト27件のデータを持って交渉に臨めるタイミングです。次いで「売上分析レポート」を4月施行後の振り返りに備えて準備しておくことを推奨します。" },
      ]} />

      {categories.map(cat=>(
        <div key={cat} style={{ marginBottom:24 }}>
          <div style={{ fontSize:13, fontWeight:800, color:T.ink4,
            letterSpacing:".08em", marginBottom:12, paddingLeft:2 }}>{cat}</div>
          <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:12 }}>
            {REPORT_DEFS.filter(r=>r.category===cat).map(rep=>(
              <div key={rep.id}
                onClick={()=>setActive(rep.id)}
                style={{ background:T.white, borderRadius:10, border:`1px solid ${T.rule}`,
                  boxShadow:T.sS, padding:"20px", cursor:"pointer", transition:"all .15s" }}
                onMouseEnter={e=>{ e.currentTarget.style.boxShadow=T.sM; e.currentTarget.style.borderColor=T.g2; }}
                onMouseLeave={e=>{ e.currentTarget.style.boxShadow=T.sS; e.currentTarget.style.borderColor=T.rule; }}>
                <div style={{ fontSize:28, marginBottom:10 }}>{rep.icon}</div>
                <div style={{ fontSize:14, fontWeight:800, color:T.ink, marginBottom:4 }}>{rep.title}</div>
                <div style={{ fontSize:12, color:T.ink4, lineHeight:1.6, marginBottom:12 }}>{rep.desc}</div>
                <div style={{ display:"flex", gap:6 }}>
                  <Btn small onClick={e=>{e.stopPropagation();setActive(rep.id);}}>開く</Btn>
                  <Btn variant="ghost" small onClick={e=>{e.stopPropagation();onToast(`「${rep.title}」PDF出力`);}}>PDF</Btn>
                </div>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

