const PublishersMasterView = ({ onToast, darkMode }) => {
  var T = darkMode ? T_DARK : T_LIGHT;
  const [pubs, setPubs]     = useState(PUBLISHERS.map(p=>(Object.assign({},p,{contacts:[],history:[]}))));
  const [selId, setSelId]   = useState(null);
  const [editId, setEditId] = useState(null);
  const [editData, setEditData] = useState(null);

  const saveEdit = () => {
    if(!editData) return;
    const parsed = {
      ...editData,
      kakuRate:     isNaN(parseFloat(editData.kakuRate))     ? editData.kakuRate     : parseFloat(editData.kakuRate),
      paymentDays:  isNaN(parseInt(editData.paymentDays))    ? editData.paymentDays  : parseInt(editData.paymentDays),
      elecShareRate:isNaN(parseFloat(editData.elecShareRate))? editData.elecShareRate: parseFloat(editData.elecShareRate),
    };
    setPubs(prev=>prev.map(p=>p.id===parsed.id?parsed:p));
    setEditId(null); setEditData(null);
    onToast("出版社情報を更新しました");
  };

  return (
    <div>
      <SectionHeader title="出版社マスタ（詳細）"
        desc="掛率・締日・電子書籍条件・担当者情報を管理" />

      <div style={{ display:"flex",flexDirection:"column",gap:10 }}>
        {pubs.map(p=>{
          const isOpen = selId===p.id;
          const isEdit = editId===p.id;
          return (
            <Card key={p.id} style={{ padding:0,overflow:"hidden",borderLeft:"4px solid "+p.color }}>
              {/* ヘッダ */}
              <div style={{ padding:"14px 20px",cursor:"pointer",
                background:isOpen?p.color+"08":T.white }}
                onClick={()=>{ setSelId(isOpen?null:p.id); setEditId(null); setEditData(null); }}>
                <div style={{ display:"flex",gap:12,alignItems:"center" }}>
                  <div style={{ width:32,height:32,borderRadius:8,background:p.color,
                    display:"flex",alignItems:"center",justifyContent:"center",
                    fontSize:12,fontWeight:800,color:"#fff",flexShrink:0 }}>
                    {p.short}
                  </div>
                  <div style={{ flex:1 }}>
                    <div style={{ fontSize:14,fontWeight:800,color:T.ink }}>{p.name}</div>
                  </div>
                  <div style={{ display:"flex",gap:16,fontSize:12 }}>
                    <div style={{ textAlign:"center" }}>
                      <div style={{ fontFamily:"'Inter'",fontWeight:700,color:p.color,fontSize:14 }}>{Math.round(p.kakuRate*100)}%</div>
                      <div style={{ fontSize:10,color:T.ink4 }}>掛率</div>
                    </div>
                    <div style={{ textAlign:"center" }}>
                      <div style={{ fontFamily:"'Inter'",fontWeight:700,color:T.ink,fontSize:14 }}>{p.paymentDays}日</div>
                      <div style={{ fontSize:10,color:T.ink4 }}>支払サイト</div>
                    </div>
                    <div style={{ textAlign:"center" }}>
                      <div style={{ fontFamily:"'Inter'",fontWeight:700,color:T.ink,fontSize:14 }}>{Math.round(p.elecShareRate*100)}%</div>
                      <div style={{ fontSize:10,color:T.ink4 }}>電子分配率</div>
                    </div>
                  </div>
                  <span style={{ fontSize:13,color:T.ink4 }}>{isOpen?"▲":"▼"}</span>
                </div>
              </div>

              {/* 詳細 */}
              {isOpen && (
                <div style={{ borderTop:"1px solid "+T.rule,padding:"16px 20px" }}>
                  {isEdit && editData ? (
                    <div>
                      <div style={{ display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:12 }}>
                        {[
                          { key:"kakuRate",     label:"掛率（例：0.65）"       },
                          { key:"paymentDays",  label:"支払サイト（日）"        },
                          { key:"elecShareRate",label:"電子分配率（例：0.60）"  },
                          { key:"negotiationNote",label:"交渉メモ"             },
                        ].map((f,i)=>(
                          <div key={i}>
                            <div style={{ fontSize:11,fontWeight:700,color:T.ink3,marginBottom:4 }}>{f.label}</div>
                            <input aria-label={f.label} value={editData[f.key]||""}
                              onChange={e=>setEditData(function(prev){ return Object.assign({},prev,Object.fromEntries([[f.key,e.target.value]])); })}
                              style={{ width:"100%",padding:"6px 10px",borderRadius:5,
                                border:"1.5px solid "+T.rule,fontSize:12,outline:"none",boxSizing:"border-box" }} />
                          </div>
                        ))}
                      </div>
                      <div style={{ display:"flex",gap:8 }}>
                        <Btn onClick={saveEdit}>💾 保存</Btn>
                        <Btn variant="ghost" onClick={()=>{ setEditId(null); setEditData(null); }}>キャンセル</Btn>
                      </div>
                    </div>
                  ) : (
                    <div>
                      <div style={{ fontSize:12,color:T.ink3,marginBottom:10,lineHeight:1.8,
                        background:T.bg,borderRadius:7,padding:"10px 14px" }}>
                        {p.negotiationNote}
                      </div>
                      <div style={{ display:"flex",gap:8 }}>
                        <Btn variant="secondary" small onClick={()=>{ setEditId(p.id); setEditData(Object.assign({}, p)); }}>✏ 編集</Btn>
                        <Btn variant="ghost" small onClick={()=>onToast("取引履歴CSV出力（デモ）")}>📤 取引履歴</Btn>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </Card>
          );
        })}
      </div>
    </div>
  );
};

