// 弁護士会員（登録番号確認済み）かどうかを判定
function isVerifiedLawyer(memberName) {
  var m = MOCK_MEMBERS.find(function(x){
    return x.name === memberName || (memberName && memberName.includes(x.name));
  });
  return !!(m && m.type === "弁護士" && m.barNo && m.barNo.length > 2);
}

