// AdminApp（ルーター・useState・renderPage・サイドバー）
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// ── クイックアクション マスタ定義 ──────────────────
const QA_MASTER = [
  { id:"qa_phone_order", icon:"🛒", label:"電話注文を入力", nav:"orders" },
  { id:"qa_sagawa_csv",  icon:"📦", label:"佐川CSV出力",    nav:"orders" },
  { id:"qa_inventory",   icon:"📋", label:"在庫管理",       nav:"inventory" },
  { id:"qa_search",      icon:"🔍", label:"横断検索",       nav:"__search__" },
  { id:"qa_dashboard",   icon:"📊", label:"ダッシュボード", nav:"dashboard" },
  { id:"qa_members",     icon:"👤", label:"会員管理",       nav:"members" },
  { id:"qa_corporate",   icon:"🏢", label:"法人アカウント", nav:"corporate" },
  { id:"qa_books",       icon:"📚", label:"書籍管理",       nav:"books" },
  { id:"qa_bpo",         icon:"⚖",  label:"BPO管理",       nav:"bpo" },
  { id:"qa_sales",       icon:"💰", label:"売上管理",       nav:"sales" },
  { id:"qa_content",     icon:"✍",  label:"コンテンツ管理", nav:"articles" },
  { id:"qa_mail",        icon:"📧", label:"メルマガ配信",   nav:"mail_campaign" },
  { id:"qa_search_log",  icon:"🔍", label:"検索ログ分析",   nav:"search_analytics" },
  { id:"qa_purchase",     icon:"📠", label:"発注記録",        nav:"purchase_orders" },
];
const QA_DEFAULT_IDS = ["qa_phone_order","qa_sagawa_csv","qa_inventory","qa_search","qa_dashboard"];

const QuickActionFab = function({ navigateTo, setSearchOpen, setSearchQ, isMobile, darkMode, qaConfig }) {
  var [qaOpen, setQaOpen] = React.useState(false);
  var TC = darkMode ? T_DARK : T_LIGHT;
  var enabledIds = (qaConfig && qaConfig.length > 0) ? qaConfig : QA_DEFAULT_IDS;
  var actions = enabledIds.map(function(qid) {
    var master = QA_MASTER.find(function(m){ return m.id === qid; });
    if (!master) return null;
    return {
      label: master.icon + " " + master.label,
      action: function() {
        if (master.nav === "__search__") {
          setSearchOpen(true); setSearchQ("");
        } else {
          navigateTo(master.nav);
        }
        setQaOpen(false);
      }
    };
  }).filter(Boolean);
  return (
    <div style={{ position:"fixed",
      bottom:isMobile?20:28, right:isMobile?"50%":176,
      transform:isMobile?"translateX(80px)":"none", zIndex:1200 }}>
      {qaOpen && (
        <div style={{ position:"absolute",bottom:"calc(100% + 10px)",right:0,
          display:"flex",flexDirection:"column",gap:6,alignItems:"flex-end" }}>
          {actions.map(function(a,i){
            return (
              <button key={i} onClick={a.action}
                style={{ padding:"8px 14px",borderRadius:8,
                  background:TC.white, border:"1px solid "+TC.rule,
                  color:TC.ink, fontSize:12,fontWeight:600,
                  cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap",
                  boxShadow:"0 2px 8px rgba(0,0,0,.15)" }}>
                {a.label}
              </button>
            );
          })}
        </div>
      )}
      <button onClick={function(){ setQaOpen(function(v){ return !v; }); }}
        style={{ width:isMobile?56:48,height:isMobile?56:48,borderRadius:"50%",
          background:qaOpen?"#555":T_LIGHT.g2, color:"#fff",border:"none",
          cursor:"pointer",fontSize:isMobile?22:20,
          boxShadow:"0 4px 16px rgba(26,92,56,.4)",
          display:"flex",alignItems:"center",justifyContent:"center" }}>
        {qaOpen?"✕":"⚡"}
      </button>
    </div>
  );
};

const TourGuide = function() {
  var [tourStep, setTourStep] = React.useState(function(){
    try { return localStorage.getItem(LS.tourDone)==="1" ? -1 : 0; }
    catch(e){ return 0; }
  });
  if(tourStep<0) return null;
  var steps = [
    { title:"👋 SLD管理画面へようこそ",
      desc:"至誠堂書店の業務管理システムです。このガイドで基本操作を説明します（全4ステップ）。",
      hint:"" },
    { title:"📦 注文管理",
      desc:"左メニューの「注文管理」では受注確認・発送承認・外商配達記録ができます。急ぎ注文は赤帯で表示されます。",
      hint:"Alt+O（Mac: Option+O）キーで注文管理に素早くジャンプできます。" },
    { title:"🔍 横断検索（Ctrl+K）",
      desc:"どのページからでも Ctrl+K（Mac: Cmd+K）を押すと注文ID・会員名・書名を横断検索できます。",
      hint:"2文字以上入力すると結果が表示されます。" },
    { title:"⚡ クイックアクション",
      desc:"画面右下の ⚡ ボタンから電話注文入力・佐川CSV出力などの頻出操作に素早くアクセスできます。",
      hint:"ブックマーク登録で頻出ページへのショートカットも作れます。" },
  ];
  var step = steps[tourStep] || steps[0];
  var isLast = tourStep === steps.length-1;
  return (
    <div style={{ position:"fixed",inset:0,background:"rgba(0,0,0,.5)",
      zIndex:10000,display:"flex",alignItems:"flex-end",
      justifyContent:"center",padding:"0 16px 40px" }}>
      <div style={{ background:"#fff",borderRadius:14,width:"100%",maxWidth:480,
        boxShadow:"0 8px 48px rgba(0,0,0,.3)",overflow:"hidden" }}>
        <div style={{ background:"linear-gradient(135deg,"+T.g1+","+T.g2+")",
          padding:"14px 18px",color:"#fff",
          display:"flex",justifyContent:"space-between",alignItems:"center" }}>
          <span style={{ fontSize:13,fontWeight:800 }}>操作ガイド {tourStep+1}/{steps.length}</span>
          <button onClick={function(){
            setTourStep(-1);
            try{ localStorage.setItem(LS.tourDone,"1"); }catch(e){}
          }} style={{ background:"transparent",border:"none",color:"rgba(255,255,255,.7)",
            cursor:"pointer",fontSize:12,fontFamily:"inherit" }}>スキップ</button>
        </div>
        <div style={{ height:3,background:"#e0e0e0" }}>
          <div style={{ height:"100%",background:T.g2,
            width:((tourStep+1)/steps.length*100)+"%",transition:"width .3s" }} />
        </div>
        <div style={{ padding:"20px 20px 16px" }}>
          <div style={{ fontSize:16,fontWeight:800,color:T.ink,marginBottom:8 }}>{step.title}</div>
          <div style={{ fontSize:13,color:T.ink3,lineHeight:1.7,marginBottom:8 }}>{step.desc}</div>
          {step.hint && (
            <div style={{ fontSize:11,color:T.g2,background:T.okPale,
              borderRadius:6,padding:"6px 10px" }}>
              💡 {step.hint}
            </div>
          )}
        </div>
        <div style={{ padding:"0 20px 18px",display:"flex",gap:8,justifyContent:"flex-end" }}>
          {tourStep>0 && (
            <button onClick={function(){ setTourStep(function(s){ return s-1; }); }}
              style={{ padding:"8px 16px",borderRadius:7,border:"1px solid #d8d4c8",
                background:"transparent",cursor:"pointer",fontSize:13,
                color:T.ink3,fontFamily:"inherit" }}>← 前へ</button>
          )}
          <button onClick={function(){
            if(isLast){ setTourStep(-1); try{ localStorage.setItem(LS.tourDone,"1"); }catch(e){} }
            else { setTourStep(function(s){ return s+1; }); }
          }} style={{ padding:"8px 20px",borderRadius:7,border:"none",
            background:T.g2,color:"#fff",cursor:"pointer",
            fontSize:13,fontWeight:700,fontFamily:"inherit" }}>
            {isLast?"✅ 使い始める":"次へ →"}
          </button>
        </div>
      </div>
    </div>
  );
};

function AdminApp() {
  // ── 画面幅監視（レスポンシブ対応）
  const [windowWidth, setWindowWidth] = useState(function(){ return typeof window!=="undefined"?window.innerWidth:1200; });
  React.useEffect(function(){
    function onResize(){ setWindowWidth(window.innerWidth); }
    window.addEventListener("resize", onResize);
    return function(){ window.removeEventListener("resize", onResize); };
  }, []);
  var isMobile  = windowWidth < BREAKPOINTS.mobile;
  var isTablet  = windowWidth >= BREAKPOINTS.mobile && windowWidth < BREAKPOINTS.tablet;
  var isNarrow  = windowWidth < BREAKPOINTS.tablet;

  // ── ダークモード
  const [darkMode, setDarkMode] = useState(function(){
    try { return localStorage.getItem(LS.darkMode)==="1"; } catch(e){ return false; }
  });
  function toggleDark() {
    setDarkMode(function(d){
      var next = !d;
      try { localStorage.setItem(LS.darkMode, next?"1":"0"); } catch(e){}
      return next;
    });
  }

  // ── スタッフロール・ログインユーザー
  const [staffRole, setStaffRole] = useState(function(){
    try { return localStorage.getItem(LS.staffRole) || "admin"; } catch(e){ return "admin"; }
  });
  const [staffName, setStaffName] = useState(function(){
    try { return localStorage.getItem("sld_staff_name") || "金子 代表"; } catch(e){ return "金子 代表"; }
  });
  const [staffStore, setStaffStore] = useState(function(){
    try { return localStorage.getItem("sld_staff_store") || "本社"; } catch(e){ return "本社"; }
  });
  // 担当フィルターのデフォルト（ロールで自動設定、個人設定で変更可）
  const [myOrdersOnly, setMyOrdersOnly] = useState(function(){
    try {
      var saved = localStorage.getItem("sld_my_orders_only");
      if (saved !== null) return saved === "true";
      var role = localStorage.getItem(LS.staffRole) || "admin";
      return roleDefaultFilter(role) === "self";
    } catch(e){ return false; }
  });

  // staffRole 変更時にデフォルトフィルターを更新
  function switchRole(newRole, newName, newStore) {
    setStaffRole(newRole);
    if (newName) setStaffName(newName);
    if (newStore) setStaffStore(newStore);
    var def = roleDefaultFilter(newRole);
    var defaultMyOnly = def === "self";
    setMyOrdersOnly(defaultMyOnly);
    try {
      localStorage.setItem(LS.staffRole, newRole);
      if (newName) localStorage.setItem("sld_staff_name", newName);
      if (newStore) localStorage.setItem("sld_staff_store", newStore);
      localStorage.setItem("sld_my_orders_only", String(defaultMyOnly));
      // ロール変更後のデフォルトページへ移動
      var rm = ROLE_META[newRole] || ROLE_META.admin;
      setPage(rm.defaultPage || "dashboard");
    } catch(e){}
  }

  // ── フォントサイズスケール（1=小14px 2=中17px 3=大20px 4=特大24px）
  const [fontScale, setFontScale] = useState(function(){
    try { return parseInt(localStorage.getItem("sld_font_scale")||"3"); } catch(e){ return 3; }
  });
  // ── 粗利率設定（手動上書き可能、localStorage保存）
  const [grossMarginMap, setGrossMarginMap] = useState(function(){
    try {
      var saved = localStorage.getItem("sld_gm_map");
      return saved ? JSON.parse(saved) : {};
    } catch(e){ return {}; }
  });
  function updateGrossMargin(id, pct) {
    setGrossMarginMap(function(prev){
      var next = Object.assign({}, prev);
      next[id] = pct;
      try { localStorage.setItem("sld_gm_map", JSON.stringify(next)); } catch(e){}
      return next;
    });
  }
  function changeFontScale(n) {
    setFontScale(n);
    try { localStorage.setItem("sld_font_scale", String(n)); } catch(e){}
  }
  // フォントスケールをCSS変数として適用
  // フォントスケール: 1=小(16px) 2=中(19px) 3=大(22px) 4=特大(26px)
  var fontBasePx = fontScale===1?16:fontScale===2?19:fontScale===3?22:fontScale===4?26:19;

  // ── グローバル検索
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchQ,    setSearchQ]    = useState("");
  // ── ロール切替メニュー
  const [roleMenuOpen, setRoleMenuOpen] = useState(false);

  // ── 通知センター
  const [notifOpen, setNotifOpen] = useState(false);

  // ── クイックアクション設定
  const [qaConfig, setQaConfig] = useState(function(){
    try {
      var s = localStorage.getItem(LS.quickActions);
      return s ? JSON.parse(s) : QA_DEFAULT_IDS;
    } catch(e){ return QA_DEFAULT_IDS; }
  });
  function updateQaConfig(newConfig) {
    setQaConfig(newConfig);
    try { localStorage.setItem(LS.quickActions, JSON.stringify(newConfig)); } catch(e){}
  }

  // ── ブックマーク
  const [bookmarks, setBookmarks] = useState(function(){
    try {
      var s = localStorage.getItem(LS.bookmarks);
      return s ? JSON.parse(s) : ["orders","members","deposits"];
    } catch(e){ return ["orders","members","deposits"]; }
  });
  function toggleBookmark(pageId) {
    setBookmarks(function(prev){
      var next = prev.includes(pageId)
        ? prev.filter(function(b){ return b!==pageId; })
        : prev.concat([pageId]);
      try { localStorage.setItem(LS.bookmarks, JSON.stringify(next)); } catch(e){}
      return next;
    });
  }

  const [page,      setPage]      = useState(function(){
    try {
      var role = localStorage.getItem(LS.staffRole) || "admin";
      return (role==="kasumigaseki"||role==="honsha") ? "orders" : "dashboard";
    } catch(e){ return "dashboard"; }
  });
  const [prevPage,  setPrevPage]  = useState(null);
  const [pageLoading, setPageLoading] = useState(false);
  const [poPrefill, setPoPrefill] = useState(null); // 発注画面へのプリフィル（ISBN/書名）
  const [collapsed, setCollapsed] = useState(false);

  // モバイル時はサイドバー自動折り畳み
  React.useEffect(function(){
    if(isMobile) setCollapsed(true);
  }, [isMobile]);

  // キーボードショートカット
  React.useEffect(function(){
    function onKey(e) {
      if((e.metaKey||e.ctrlKey) && e.key==="k"){
        e.preventDefault(); setSearchOpen(function(v){ return !v; }); setSearchQ(""); return;
      }
      if(e.key==="Escape"){ setSearchOpen(false); setNotifOpen(false); return; }
      if(e.target.tagName==="INPUT"||e.target.tagName==="TEXTAREA") return;
      if(e.altKey) {
        if(e.key==="d"){ e.preventDefault(); navigateTo("dashboard"); }
        if(e.key==="o"){ e.preventDefault(); navigateTo("orders"); }
        if(e.key==="m"){ e.preventDefault(); navigateTo("members"); }
        if(e.key==="s"){ e.preventDefault(); navigateTo("sales"); }
      }
    }
    window.addEventListener("keydown", onKey);
    return function(){ window.removeEventListener("keydown", onKey); };
  }, []);

  // ページ遷移（前ページを記録）
  function navigateTo(nextPage) {
    setPrevPage(page);
    setPageLoading(true);
    setPage(nextPage);
    setTimeout(function(){ setPageLoading(false); }, 300);
  }

  // ダッシュボードに戻る
  function goBack() {
    setPageLoading(true);
    if(prevPage) {
      setPage(prevPage);
      setPrevPage(null);
    } else {
      setPage("dashboard");
      setPrevPage(null);
    }
    setTimeout(function(){ setPageLoading(false); }, 300);
  }
  const [toast,     setToast]     = useState("");
  const [undoState, setUndoState] = useState(null);
  // undoState: { msg, restore: function } or null
  const [aiOpen,    setAiOpen]    = useState(false);
  // 注文データをグローバルで共有（OrdersView・ReconciliationView間の連動）
  // ─── localStorage から復元 ───────────────────────────────
  const [globalOrders, setGlobalOrders] = useState(function(){
    try {
      const saved = localStorage.getItem(LS.orders);
      return saved ? JSON.parse(saved) : MOCK_ORDERS.map(function(o){ return Object.assign({},o); });
    } catch(e) {
      return MOCK_ORDERS.map(function(o){ return Object.assign({},o); });
    }
  });

  const [globalDeposits, setGlobalDeposits] = useState(function(){
    try {
      const saved = localStorage.getItem(LS.deposits);
      return saved ? JSON.parse(saved) : MOCK_DEPOSITS.map(function(d){ return Object.assign({},d); });
    } catch(e) {
      return MOCK_DEPOSITS.map(function(d){ return Object.assign({},d); });
    }
  });

  // ── グローバル法人データ（CorporateView + OrdersView で共有）
  const [globalCorps, setGlobalCorps] = useState(function(){
    try {
      const saved = localStorage.getItem('sld_corps');
      return saved ? JSON.parse(saved) : MOCK_CORPS.map(c => Object.assign({}, c));
    } catch(e) { return MOCK_CORPS.map(c => Object.assign({}, c)); }
  });

  // globalCorps 変更時にlocalStorageへ保存
  React.useEffect(function(){
    try { localStorage.setItem('sld_corps', JSON.stringify(globalCorps)); } catch(e){}
  }, [globalCorps]);

  // 佐川集荷時刻（設定変更可能）
  const [sagawaDeadline, setSagawaDeadline] = useState(function(){
    try {
      return localStorage.getItem(LS.sagawaDeadline) || "16:30";
    } catch(e) { return "16:30"; }
  });

  // 本日の霞が関→本社 中継確認記録
  const [transitRecord, setTransitRecord] = useState(function(){
    try {
      const today = new Date().toISOString().slice(0,10);
      const saved = localStorage.getItem(LS.transit+today);
      return saved ? JSON.parse(saved) : { done:false, time:null, by:null };
    } catch(e) { return { done:false, time:null, by:null }; }
  });

  // 会員データをグローバルで管理（修習生ステータス・エキスパート認定をリアルタイム更新）
  const [globalMembers, setGlobalMembers] = useState(function(){
    try {
      const saved = localStorage.getItem(LS.members);
      return saved ? JSON.parse(saved) : MOCK_MEMBERS.map(function(m){ return Object.assign({},m); });
    } catch(e) {
      return MOCK_MEMBERS.map(function(m){ return Object.assign({},m); });
    }
  });

  // 改訂版通知の送信済み書籍IDを管理
  const [globalSentRevisions, setGlobalSentRevisions] = useState(function(){
    try {
      const saved = localStorage.getItem(LS.sentRevisions);
      return saved ? JSON.parse(saved) : [];
    } catch(e) { return []; }
  });

  const [globalAddrHistory, setGlobalAddrHistory] = useState(function(){
    try {
      const saved = localStorage.getItem(LS.addrHistory);
      return saved ? JSON.parse(saved) : [];
    } catch(e) { return []; }
  });
  // フィードバック
  const [fbOpen,    setFbOpen]    = useState(false);
  const [fbType,    setFbType]    = useState("improvement");
  const [fbPriority,setFbPriority]= useState("medium");
  const [fbContent, setFbContent] = useState("");
  const [fbEmoji,   setFbEmoji]   = useState(null);
  const [fbItems,   setFbItems]   = useState(FEEDBACK_DATA_INIT.map(f=>(Object.assign({}, f))));
  const timerRef = useRef(null);
  const totalBadge = NAV.filter(s=>!s.shortcutGroup).flatMap(s=>s.items).reduce((n,i)=>n+(i.badge&&!isNaN(+i.badge)?parseInt(i.badge):0),0);

  // ─── localStorage への自動保存 ──────────────────────────
  React.useEffect(function(){
    try { localStorage.setItem(LS.orders, JSON.stringify(globalOrders)); }
    catch(e){}
  }, [globalOrders]);

  React.useEffect(function(){
    try { localStorage.setItem(LS.deposits, JSON.stringify(globalDeposits)); }
    catch(e){}
  }, [globalDeposits]);

  React.useEffect(function(){
    try { localStorage.setItem(LS.members, JSON.stringify(globalMembers)); }
    catch(e){}
  }, [globalMembers]);

  React.useEffect(function(){
    try { localStorage.setItem(LS.sentRevisions, JSON.stringify(globalSentRevisions)); }
    catch(e){}
  }, [globalSentRevisions]);

  React.useEffect(function(){
    try { localStorage.setItem(LS.addrHistory, JSON.stringify(globalAddrHistory)); }
    catch(e){}
  }, [globalAddrHistory]);

  // ─── 集中管理関数（UNDO対応・全4 state）─────────────────
  // undoMsg を渡すと5秒間「元に戻す」ボタン付きトーストを表示する
  function updateOrder(id, patch, undoMsg) {
    setGlobalOrders(function(prev){
      if(undoMsg) {
        const snapshot = prev.slice();
        showUndoToast(undoMsg, function(){ setGlobalOrders(snapshot); });
      }
      return prev.map(function(o){ return o.id===id ? Object.assign({},o,patch) : o; });
    });
  }

  function addOrder(newOrd, undoMsg) {
    setGlobalOrders(function(prev){
      if(undoMsg) {
        const snapshot = prev.slice();
        showUndoToast(undoMsg, function(){ setGlobalOrders(snapshot); });
      }
      return [newOrd, ...prev];
    });
  }

  function updateDeposit(id, patch, undoMsg) {
    setGlobalDeposits(function(prev){
      if(undoMsg) {
        const snapshot = prev.slice();
        showUndoToast(undoMsg, function(){ setGlobalDeposits(snapshot); });
      }
      return prev.map(function(d){ return d.id===id ? Object.assign({},d,patch) : d; });
    });
  }

  function resetOrders() {
    const fresh = MOCK_ORDERS.map(function(o){ return Object.assign({},o); });
    setGlobalOrders(fresh);
    try { localStorage.removeItem("sld_orders"); } catch(e){}
  }

  function resetDeposits() {
    const fresh = MOCK_DEPOSITS.map(function(d){ return Object.assign({},d); });
    setGlobalDeposits(fresh);
    try { localStorage.removeItem("sld_deposits"); } catch(e){}
  }

  function updateMember(id, patch, undoMsg) {
    setGlobalMembers(function(prev){
      if(undoMsg) {
        const snapshot = prev.slice();
        showUndoToast(undoMsg, function(){ setGlobalMembers(snapshot); });
      }
      return prev.map(function(m){ return m.id===id ? Object.assign({},m,patch) : m; });
    });
  }

  function resetMembers() {
    const fresh = MOCK_MEMBERS.map(function(m){ return Object.assign({},m); });
    setGlobalMembers(fresh);
    try { localStorage.removeItem("sld_members"); } catch(e){}
  }

  // 佐川集荷時刻の更新
  function updateSagawaDeadline(time) {
    setSagawaDeadline(time);
    try { localStorage.setItem(LS.sagawaDeadline, time); } catch(e){}
  }

  // 霞が関→本社 中継確認を記録
  function confirmTransit(staffName) {
    const now = new Date();
    const hhmm = now.getHours().toString().padStart(2,"0")+":"+now.getMinutes().toString().padStart(2,"0");
    const rec = { done:true, time:hhmm, by:staffName };
    setTransitRecord(rec);
    try {
      const today = now.toISOString().slice(0,10);
      localStorage.setItem(LS.transit+today, JSON.stringify(rec));
    } catch(e){}
  }

  function markRevisionSent(bookId, undoMsg) {
    setGlobalSentRevisions(function(prev){
      if(undoMsg) {
        const snapshot = prev.slice();
        showUndoToast(undoMsg, function(){ setGlobalSentRevisions(snapshot); });
      }
      return prev.indexOf(bookId) >= 0 ? prev : prev.concat([bookId]);
    });
  }

  // ─── トースト表示（UNDO付き対応）──────────────────────
  const undoTimerRef = useRef(null);

  const showToast = function(msg) {
    setToast(msg);
    setUndoState(null);
    clearTimeout(timerRef.current);
    clearTimeout(undoTimerRef.current);
    timerRef.current = setTimeout(function(){ setToast(""); }, 2400);
  };

  // UNDO付きトースト（5秒間「元に戻す」ボタンを表示）
  const showUndoToast = function(msg, restoreFn) {
    setToast(msg);
    setUndoState({ msg:msg, restore:restoreFn });
    clearTimeout(timerRef.current);
    clearTimeout(undoTimerRef.current);
    timerRef.current = setTimeout(function(){
      setToast(""); setUndoState(null);
    }, 5000);
  };

  // UNDOを実行する関数
  const execUndo = function() {
    if(!undoState) return;
    undoState.restore();
    clearTimeout(timerRef.current);
    clearTimeout(undoTimerRef.current);
    setToast("↩ 元に戻しました");
    setUndoState(null);
    timerRef.current = setTimeout(function(){ setToast(""); }, 2000);
  };

  const submitFeedback = () => {
    if(!fbContent.trim() && !fbEmoji) { showToast("内容を入力してください"); return; }
    const newItem = {
      id:"fb"+Date.now(), created: new Date().toLocaleString("ja-JP"),
      staff:"田中（霞が関店）", page:page,
      type:fbType, priority:fbPriority,
      content: fbEmoji ? ("絵文字反応: "+fbEmoji+(fbContent?" / "+fbContent:"")) : fbContent,
      status:"open", note:"", emoji:fbEmoji,
    };
    setFbItems(prev=>[newItem,...prev]);
    setFbOpen(false); setFbContent(""); setFbEmoji(null);
    showToast("✅ フィードバックを送信しました。ありがとうございます！");
  };

  // ワンタップ絵文字専用: stale closure を回避するため emoji を直接引数で受け取る
  const submitEmojiReaction = (emoji) => {
    const newItem = {
      id:"fb"+Date.now(), created: new Date().toLocaleString("ja-JP"),
      staff:"田中（霞が関店）", page:page,
      type:"other", priority:"medium",
      content:"絵文字反応: "+emoji,
      status:"open", note:"", emoji:emoji,
    };
    setFbItems(prev=>[newItem,...prev]);
    setFbOpen(false); setFbEmoji(null); setFbContent("");
    showToast("✅ "+emoji+" フィードバックを送信しました！");
  };

  // ── useMemoキャッシュ（描画コスト削減）──────────────────
  var kpiCounts = React.useMemo(function(){
    var pending   = globalOrders.filter(function(o){ return o.status==="pending"; }).length;
    var holdCount = globalOrders.filter(function(o){ return o.shipApproved===false&&o.status==="pending"&&o.fmt==="paper"; }).length;
    var urgentCount = globalOrders.filter(function(o){ return o.urgent&&o.status==="pending"; }).length;
    var unmatch  = (globalDeposits||[]).filter(function(d){ return d.status==="unmatched"||d.status==="pending_ai"; }).length;
    var shipped  = globalOrders.filter(function(o){ return o.status==="shipped"; }).length;
    var delivered= globalOrders.filter(function(o){ return o.status==="delivered"; }).length;
    var direct   = globalOrders.filter(function(o){ return o.shipMethod==="direct"&&(o.status==="pending"||o.status==="delivering"); }).length;
    return { pending:pending, holdCount:holdCount, urgentCount:urgentCount,
             unmatch:unmatch, shipped:shipped, delivered:delivered, direct:direct };
  }, [globalOrders, globalDeposits]);

  const renderPage = () => {
    if (pageLoading) {
      if (page === "dashboard") return <SkeletonDashboard />;
      return <SkeletonList />;
    }
    switch(page) {
      case "dashboard":  return <DashboardView onNav={navigateTo} darkMode={darkMode} staffRole={staffRole} staffName={staffName} orders={globalOrders} deposits={globalDeposits} grossMarginMap={grossMarginMap} updateGrossMargin={updateGrossMargin} />;
      case "books":      return <BooksView onToast={showToast} sentRevisions={globalSentRevisions} markRevisionSent={markRevisionSent} darkMode={darkMode} />;
      case "orders":        return <OrdersView onToast={showToast} globalOrders={globalOrders} setGlobalOrders={setGlobalOrders} updateOrder={updateOrder} addOrder={addOrder} globalAddrHistory={globalAddrHistory} setGlobalAddrHistory={setGlobalAddrHistory} sagawaDeadline={sagawaDeadline} transitRecord={transitRecord} confirmTransit={confirmTransit} globalDeposits={globalDeposits} globalCorps={globalCorps} setGlobalCorps={setGlobalCorps} darkMode={darkMode} staffRole={staffRole} staffName={staffName} myOrdersOnly={myOrdersOnly} setMyOrdersOnly={setMyOrdersOnly} onPurchaseOrder={function(isbn,title){ setPoPrefill({isbn:isbn,title:title}); navigateTo("purchase_orders"); }} />;
      case "reconciliation": return <ReconciliationView onToast={showToast} globalOrders={globalOrders} setGlobalOrders={setGlobalOrders} updateOrder={updateOrder} updateDeposit={updateDeposit} globalDeposits={globalDeposits} setGlobalDeposits={setGlobalDeposits} darkMode={darkMode} />;
      case "stores":          return <StoreView onToast={showToast} darkMode={darkMode} />;
      case "bpo":        return <BpoView onToast={showToast} darkMode={darkMode} />;
      case "reviews":    return <ReviewsView onToast={showToast} darkMode={darkMode} />;
      case "elec_req":   return <ElecReqView onToast={showToast} darkMode={darkMode} />;
      case "mail_tx":    return <MailView mode="tx" onToast={showToast} globalMembers={globalMembers} updateMember={updateMember} darkMode={darkMode} />;
      case "mail_ma":    return <MailView mode="ma" onToast={showToast} globalMembers={globalMembers} updateMember={updateMember} darkMode={darkMode} />;
      case "pub_report": return <PubReportView onToast={showToast} darkMode={darkMode} />;
      case "points":     return <PointsView onToast={showToast} darkMode={darkMode} />;
      case "corporate":  return <CorporateView onToast={showToast} globalOrders={globalOrders} updateOrder={updateOrder} globalAddrHistory={globalAddrHistory} globalCorps={globalCorps} setGlobalCorps={setGlobalCorps} darkMode={darkMode} />;
      case "saas":       return <SaasView onToast={showToast} darkMode={darkMode} />;
      case "purchase_orders": return <PurchaseOrdersView onToast={showToast} darkMode={darkMode} prefill={poPrefill} onClearPrefill={function(){setPoPrefill(null);}} />;
      case "inventory":  return <InventoryView onToast={showToast} darkMode={darkMode} />;
      case "members":    return <MembersView onToast={showToast} globalMembers={globalMembers} updateMember={updateMember} darkMode={darkMode} />;
      case "sales":      return <SalesView onToast={showToast} darkMode={darkMode} />;
      case "gross_profit": return <GrossProfitView onToast={showToast} darkMode={darkMode} />;
      case "search_analytics":  return <SearchAnalyticsView onToast={showToast} darkMode={darkMode} />;
      case "reports":           return <ReportsView onToast={showToast} onNav={setPage} darkMode={darkMode} />;
      case "digital_products":  return <DigitalProductsView onToast={showToast} initialTab="products" darkMode={darkMode} />;
      case "digital_purchases": return <DigitalProductsView onToast={showToast} initialTab="purchases" darkMode={darkMode} />;
      case "digital_coupons":   return <DigitalProductsView onToast={showToast} initialTab="coupons" darkMode={darkMode} />;
      case "digital_analytics": return <DigitalProductsView onToast={showToast} initialTab="analytics" darkMode={darkMode} />;
      case "publishing":        return <DigitalProductsView onToast={showToast} initialTab="publishing" darkMode={darkMode} />;
      case "hero_slider":       return <HeroSliderView onToast={showToast} darkMode={darkMode} />;
      case "banners":           return <BannerAdView onToast={showToast} darkMode={darkMode} />;
      case "mail_ad":           return <MailAdView onToast={showToast} darkMode={darkMode} />;
      case "articles":          return <ContentView onToast={showToast} darkMode={darkMode} />;
      case "torikeshi":             return <TorikeshiView onToast={showToast} darkMode={darkMode} />;
      case "stripe":                return <StripeView onToast={showToast} darkMode={darkMode} />;
      case "reform_cal":            return <ReformCalView onToast={showToast} darkMode={darkMode} />;
      case "bpo_72":                return <Bpo72CheckView onToast={showToast} darkMode={darkMode} />;
      case "legalscape":            return <LegalscapeView onToast={showToast} darkMode={darkMode} />;
      case "publishers":            return <PublishersMasterView onToast={showToast} darkMode={darkMode} />;
      case "staff":                 return <StaffView onToast={showToast} darkMode={darkMode} />;
      case "settings":              return <SettingsView onToast={showToast} darkMode={darkMode} qaConfig={qaConfig} updateQaConfig={updateQaConfig} />;
      case "feedback_mgmt":        return <FeedbackMgmtView onToast={showToast} fbItems={fbItems} setFbItems={setFbItems} darkMode={darkMode} />;
      default:                  return <PlaceholderView id={page} />;
    }
  };

  return (
    <>
      <style>{`
        *,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
        body{font-family:"Noto Sans JP","Hiragino Sans",sans-serif;background:${darkMode?T_DARK.bg:T_LIGHT.bg};color:${darkMode?T_DARK.ink:T_LIGHT.ink};font-size:${fontBasePx}px;}
        h2,h3{font-weight:inherit;}
        @keyframes slideIn{from{opacity:0;transform:translateY(8px);}to{opacity:1;transform:translateY(0);}}
        @keyframes skeletonPulse{0%{background-position:200% 0;}100%{background-position:-200% 0;}}
        button{font-family:inherit;}input{font-family:inherit;}
        @media print{
          nav,aside,.no-print,[data-noprint]{display:none!important;}
          main{padding:0!important;overflow:visible!important;}
          body{font-size:11pt;color:#000;background:#fff;}
          .delivery-card{break-inside:avoid;border:1px solid #ccc!important;margin-bottom:8pt!important;}
          *{-webkit-print-color-adjust:exact;print-color-adjust:exact;}
        }
        ::-webkit-scrollbar{width:4px;height:4px;}
        ::-webkit-scrollbar-track{background:transparent;}
        ::-webkit-scrollbar-thumb{background:${T.rule2};border-radius:2px;}
      `}</style>
      <div style={{ display:"flex", height:"100vh", overflow:"hidden" }}>
        <Sidebar active={page} onNav={navigateTo} collapsed={collapsed} onCollapse={function(){ setCollapsed(function(c){ return !c; }); }} globalOrders={globalOrders} globalDeposits={globalDeposits} globalMembers={globalMembers} kpiCounts={kpiCounts} darkMode={darkMode} staffRole={staffRole} staffName={staffName} staffStore={staffStore} />
        <div style={{ flex:1, display:"flex", flexDirection:"column", overflow:"hidden" }}>
          <header style={{ background:T.white, borderBottom:`1px solid ${T.rule}`,
            padding:"0 24px", height:50, display:"flex", alignItems:"center",
            gap:14, flexShrink:0 }}>
            <button onClick={()=>setCollapsed(!collapsed)} style={{ background:"none",
              border:`1px solid ${T.rule}`, borderRadius:4, padding:"4px 8px",
              cursor:"pointer", color:T.ink4, fontSize:12 }}>
              {collapsed?"▶":"◀"}
            </button>
            <input aria-label="横断検索" placeholder="書籍・会員・注文・案件を横断検索..."
              style={{ width:"100%", maxWidth:340, padding:"7px 14px",
                borderRadius:6, border:`1px solid ${T.rule}`,
                fontSize:13, background:T.bg, outline:"none" }} />
            <div style={{ marginLeft:"auto", display:"flex", gap:10, alignItems:"center" }}>
              {(function(){
                var kpi = kpiCounts || { urgentCount:0, holdCount:0, unmatch:0 };
                var sentRevCount = (globalSentRevisions||[]).filter(function(r){ return !r.sent; }).length;
                var notifBadge = kpi.urgentCount + kpi.holdCount + kpi.unmatch + sentRevCount;
                var notifItems = [];
                if (kpi.urgentCount > 0) notifItems.push({ icon:"🚨", label:"急ぎ注文", count:kpi.urgentCount, color:T.red, bg:T.redPale, nav:"orders" });
                if (kpi.holdCount > 0)   notifItems.push({ icon:"🔒", label:"発送保留", count:kpi.holdCount, color:T.amber, bg:T.amberPale, nav:"orders" });
                if (kpi.unmatch > 0)     notifItems.push({ icon:"🏦", label:"未照合入金", count:kpi.unmatch, color:T.amber, bg:T.amberPale, nav:"deposits" });
                if (sentRevCount > 0)    notifItems.push({ icon:"🔄", label:"改訂版未送付", count:sentRevCount, color:T.navy, bg:T.navyPale, nav:"books" });
                return (
                  <div style={{ position:"relative" }}>
                    <button onClick={function(){ setNotifOpen(function(v){ return !v; }); }}
                      aria-label="通知パネル"
                      title={"未処理: 急ぎ"+kpi.urgentCount+"件 / 保留"+kpi.holdCount+"件 / 未照合"+kpi.unmatch+"件"+(sentRevCount>0?" / 改訂未送付"+sentRevCount+"件":"")}
                      style={{ position:"relative", background:"none", border:"none",
                        cursor:"pointer", fontSize:18, padding:"4px 6px" }}>
                      🔔
                      {notifBadge>0 && (
                        <span style={{ position:"absolute", top:0, right:0, background:T.red,
                          color:"#fff", fontSize:10, fontWeight:700, width:16, height:16,
                          borderRadius:"50%", display:"flex", alignItems:"center", justifyContent:"center" }}>
                          {notifBadge}
                        </span>
                      )}
                    </button>
                    {/* 通知パネル */}
                    {notifOpen && (
                      <div style={{ position:"absolute", top:"calc(100% + 8px)", right:0,
                        width:320, background:T.white, borderRadius:12,
                        border:"1px solid "+T.rule, boxShadow:"0 8px 32px rgba(0,0,0,.18)",
                        zIndex:1300, overflow:"hidden" }}>
                        {/* ヘッダー */}
                        <div style={{ padding:"12px 16px", borderBottom:"1px solid "+T.rule,
                          display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                          <span style={{ fontSize:13, fontWeight:800, color:T.ink }}>🔔 通知</span>
                          <button onClick={function(){ setNotifOpen(false); }}
                            aria-label="閉じる"
                            style={{ background:"none", border:"none", cursor:"pointer",
                              color:T.ink4, fontSize:12 }}>✕</button>
                        </div>
                        {/* 通知アイテム */}
                        <div style={{ maxHeight:320, overflowY:"auto" }}>
                          {notifItems.length === 0 ? (
                            <div style={{ padding:"24px 16px", textAlign:"center",
                              color:T.ink4, fontSize:12 }}>
                              ✅ 未処理の通知はありません
                            </div>
                          ) : (
                            notifItems.map(function(item, idx) {
                              return (
                                <button key={idx}
                                  onClick={function(){ navigateTo(item.nav); setNotifOpen(false); }}
                                  style={{ width:"100%", padding:"12px 16px", border:"none",
                                    borderBottom:"1px solid "+T.rule, background:T.white,
                                    cursor:"pointer", fontFamily:"inherit", textAlign:"left",
                                    display:"flex", alignItems:"center", gap:10,
                                    transition:"background .1s" }}
                                  onMouseEnter={function(e){ e.currentTarget.style.background=item.bg; }}
                                  onMouseLeave={function(e){ e.currentTarget.style.background=T.white; }}>
                                  <span style={{ fontSize:18, flexShrink:0 }}>{item.icon}</span>
                                  <div style={{ flex:1 }}>
                                    <div style={{ fontSize:12, fontWeight:700, color:T.ink }}>{item.label}</div>
                                    <div style={{ fontSize:10, color:T.ink4, marginTop:1 }}>クリックで該当画面へ</div>
                                  </div>
                                  <span style={{ fontSize:16, fontWeight:800, color:item.color,
                                    background:item.bg, padding:"2px 10px", borderRadius:8,
                                    fontFamily:"'Inter',sans-serif" }}>
                                    {item.count}
                                  </span>
                                </button>
                              );
                            })
                          )}
                        </div>
                        {/* フッター */}
                        <div style={{ padding:"8px 16px", borderTop:"1px solid "+T.rule,
                          background:T.bg }}>
                          <button onClick={function(){ navigateTo("dashboard"); setNotifOpen(false); }}
                            style={{ width:"100%", padding:"6px", borderRadius:6,
                              border:"1px solid "+T.rule, background:T.white,
                              cursor:"pointer", fontFamily:"inherit",
                              fontSize:11, fontWeight:600, color:T.g2 }}>
                            📊 ダッシュボードで全体を確認
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                );
              })()}
              {/* フォントサイズ調整 */}
              <div style={{ display:"flex",alignItems:"center",gap:1,
                background:"rgba(255,255,255,.15)",borderRadius:8,padding:"3px 4px",
                border:"1px solid rgba(255,255,255,.25)" }}>
                <span style={{ fontSize:10,color:"rgba(255,255,255,.6)",
                  paddingRight:4,paddingLeft:2,fontWeight:700 }}>文字</span>
                {[
                  {n:1,lbl:"小",tip:"小（14px）"},
                  {n:2,lbl:"中",tip:"中（17px）"},
                  {n:3,lbl:"大",tip:"大（20px）"},
                  {n:4,lbl:"特大",tip:"特大（24px）"},
                ].map(function(s){
                  var isSel=fontScale===s.n;
                  return (
                    <button key={s.n}
                      onClick={function(){ changeFontScale(s.n); }}
                      title={s.tip}
                      style={{ padding:"4px 8px",borderRadius:6,cursor:"pointer",
                        fontFamily:"inherit",fontWeight:isSel?800:500,
                        fontSize:10+s.n,
                        background:isSel?"rgba(255,255,255,.35)":"transparent",
                        color:isSel?"#fff":"rgba(255,255,255,.6)",
                        border:"none",lineHeight:1,transition:"all .15s" }}>
                      {s.lbl}
                    </button>
                  );
                })}
              </div>

              {/* ロールバッジ + クイック切替 */}
              {(function(){
                var crm = ROLE_META[staffRole]||ROLE_META.admin;
                return (
                  <div style={{ position:"relative" }}>
                    <div onClick={function(){ setRoleMenuOpen(function(v){ return !v; }); }}
                      style={{ display:"flex",alignItems:"center",gap:6,
                        padding:"4px 10px",borderRadius:20,cursor:"pointer",
                        background:crm.bg,border:"1px solid "+crm.color+"40" }}
                      title="クリックでロール切替">
                      <span style={{ fontSize:13 }}>{crm.icon}</span>
                      <span style={{ fontSize:11,fontWeight:700,color:crm.color }}>
                        {(staffName||"ゲスト").replace(/ .*/,"")}
                      </span>
                      <span style={{ fontSize:10,color:crm.color+"80" }}>▼</span>
                    </div>
                    {/* ロール切替ドロップダウン */}
                    {roleMenuOpen && (
                      <div style={{ position:"absolute",top:"100%",right:0,
                        background:T.white,borderRadius:10,marginTop:4,
                        boxShadow:"0 4px 24px rgba(0,0,0,.15)",
                        border:"1px solid "+T.rule,zIndex:200,
                        minWidth:200,overflow:"hidden" }}>
                        <div style={{ padding:"8px 12px",fontSize:10,
                          fontWeight:700,color:T.ink4,borderBottom:"1px solid "+T.rule }}>
                          デモ用ロール切替
                        </div>
                        {Object.entries(ROLE_META).map(function(entry){
                          var k=entry[0]; var v=entry[1];
                          var isActive = staffRole===k;
                          return (
                            <button key={k}
                              onClick={function(){
                                var demoNames = {
                                  admin:"金子 代表",owner:"鈴木 社長",
                                  gaishoo:"田中 外商",ops:"林 出荷",
                                  content:"佐藤 編集",store:"山田 店舗",
                                };
                                switchRole(k, demoNames[k]||k, "本社");
                                setRoleMenuOpen(false);
                                showToast("ロールを「"+v.label+"」に切替しました");
                              }}
                              style={{ display:"flex",alignItems:"center",gap:8,
                                width:"100%",padding:"10px 14px",border:"none",
                                cursor:"pointer",fontFamily:"inherit",textAlign:"left",
                                background:isActive?v.bg:"transparent",
                                borderBottom:"1px solid "+T.rule }}>
                              <span style={{ fontSize:16 }}>{v.icon}</span>
                              <div style={{ flex:1 }}>
                                <div style={{ fontSize:12,fontWeight:isActive?700:400,
                                  color:isActive?v.color:T.ink }}>{v.label}</div>
                                <div style={{ fontSize:10,color:T.ink4 }}>{v.desc.slice(0,30)}...</div>
                              </div>
                              {isActive && <span style={{ fontSize:10,color:v.color,fontWeight:700 }}>現在</span>}
                            </button>
                          );
                        })}
                      </div>
                    )}
                  </div>
                );
              })()}
            </div>
          </header>
          <main style={{ flex:1, overflowY:"auto", padding:0, background:darkMode?T_DARK.bg:T_LIGHT.bg }}>
            {/* ── ダッシュボードへ戻るバー ── */}
            {prevPage==="dashboard" && (
              <div style={{ padding:"8px 24px",
                background:"linear-gradient(90deg,"+T.g1+"f0,"+T.g2+"f0)",
                display:"flex",alignItems:"center",gap:10,
                borderBottom:"2px solid "+T.gold+"40",
                position:"sticky",top:0,zIndex:50 }}>
                <button onClick={goBack}
                  style={{ display:"flex",alignItems:"center",gap:6,
                    background:"rgba(255,255,255,.15)",
                    border:"1px solid rgba(255,255,255,.3)",
                    borderRadius:6,padding:"5px 14px",
                    color:"#fff",fontSize:12,fontWeight:700,
                    cursor:"pointer",fontFamily:"inherit",
                    transition:"background .12s" }}
                  onMouseEnter={function(e){ e.currentTarget.style.background="rgba(255,255,255,.25)"; }}
                  onMouseLeave={function(e){ e.currentTarget.style.background="rgba(255,255,255,.15)"; }}>
                  ← ダッシュボードに戻る
                </button>
                <span style={{ fontSize:11,color:"rgba(255,255,255,.6)" }}>
                  ダッシュボードの指標から遷移
                </span>
              </div>
            )}
            <div style={{ padding:24 }}>
              {renderPage()}
            </div>
          </main>
        </div>
      </div>
      {/* ── グローバル検索モーダル（Cmd+K） ── */}
      {searchOpen && (
        <div onClick={function(){ setSearchOpen(false); }}
          style={{ position:"fixed",inset:0,background:"rgba(0,0,0,.6)",
            zIndex:9000,display:"flex",alignItems:"flex-start",
            justifyContent:"center",padding:"80px 16px 16px" }}>
          <div onClick={function(e){ e.stopPropagation(); }}
            style={{ background:darkMode?T_DARK.surface:T_LIGHT.white,
              borderRadius:12,width:"100%",maxWidth:560,
              boxShadow:"0 16px 48px rgba(0,0,0,.35)",overflow:"hidden" }}>
            <div style={{ display:"flex",alignItems:"center",gap:10,
              padding:"14px 18px",
              borderBottom:"1px solid "+(darkMode?T_DARK.rule:T_LIGHT.rule) }}>
              <span style={{ fontSize:18,opacity:.5 }}>🔍</span>
              <input aria-label="全体検索" autoFocus value={searchQ}
                onChange={function(e){ setSearchQ(e.target.value); }}
                placeholder="注文ID・会員名・書名で検索…（2文字以上）"
                style={{ flex:1,border:"none",outline:"none",fontSize:15,
                  background:"transparent",
                  color:darkMode?T_DARK.ink:T_LIGHT.ink,fontFamily:"inherit" }} />
              <kbd style={{ fontSize:10,padding:"2px 6px",borderRadius:4,flexShrink:0,
                background:darkMode?T_DARK.rule:T_LIGHT.rule,
                color:darkMode?T_DARK.ink4:T_LIGHT.ink4 }}>ESC</kbd>
            </div>
            {searchQ.length>=2 ? (function(){
              var TC=darkMode?T_DARK:T_LIGHT; var q=searchQ;
              var oh=globalOrders.filter(function(o){ return o.id.includes(q)||o.member.includes(q)||(o.items&&o.items.includes(q)); }).slice(0,5);
              var mh=(globalMembers||MOCK_MEMBERS).filter(function(m){ return m.name.includes(q); }).slice(0,3);
              var bh=MOCK_BOOKS.filter(function(b){ return b.title.includes(q)||b.author.includes(q); }).slice(0,3);
              var total=oh.length+mh.length+bh.length;
              if(total===0) return <div style={{ padding:"24px",textAlign:"center",color:TC.ink4,fontSize:13 }}>「{q}」の検索結果はありません</div>;
              return (
                <div style={{ maxHeight:"60vh",overflowY:"auto" }}>
                  {oh.length>0&&<div><div style={{ padding:"6px 18px",fontSize:10,fontWeight:700,color:TC.ink4,background:TC.bg }}>🛒 注文</div>
                    {oh.map(function(o,i){ return <div key={i} onClick={function(){ navigateTo("orders"); setSearchOpen(false); }} style={{ padding:"10px 18px",cursor:"pointer",fontSize:12,color:TC.ink,borderBottom:"1px solid "+TC.rule }} onMouseEnter={function(e){ e.currentTarget.style.background=TC.rule; }} onMouseLeave={function(e){ e.currentTarget.style.background="transparent"; }}>{o.id} — {o.member} ¥{o.total.toLocaleString()}</div>; })}</div>}
                  {mh.length>0&&<div><div style={{ padding:"6px 18px",fontSize:10,fontWeight:700,color:TC.ink4,background:TC.bg }}>👤 会員</div>
                    {mh.map(function(m,i){ return <div key={i} onClick={function(){ navigateTo("members"); setSearchOpen(false); }} style={{ padding:"10px 18px",cursor:"pointer",fontSize:12,color:TC.ink,borderBottom:"1px solid "+TC.rule }} onMouseEnter={function(e){ e.currentTarget.style.background=TC.rule; }} onMouseLeave={function(e){ e.currentTarget.style.background="transparent"; }}>{m.name} ({m.type})</div>; })}</div>}
                  {bh.length>0&&<div><div style={{ padding:"6px 18px",fontSize:10,fontWeight:700,color:TC.ink4,background:TC.bg }}>📚 書籍</div>
                    {bh.map(function(b,i){ return <div key={i} onClick={function(){ navigateTo("books"); setSearchOpen(false); }} style={{ padding:"10px 18px",cursor:"pointer",fontSize:12,color:TC.ink,borderBottom:"1px solid "+TC.rule }} onMouseEnter={function(e){ e.currentTarget.style.background=TC.rule; }} onMouseLeave={function(e){ e.currentTarget.style.background="transparent"; }}>{b.title} ({b.stock}冊)</div>; })}</div>}
                  <div style={{ padding:"6px 18px",fontSize:10,color:TC.ink4 }}>合計 {total}件</div>
                </div>
              );
            })() : (
              <div style={{ padding:"14px 18px" }}>
                <div style={{ fontSize:10,fontWeight:700,marginBottom:8,color:darkMode?T_DARK.ink4:T_LIGHT.ink4 }}>クイックナビ</div>
                <div style={{ display:"flex",flexWrap:"wrap",gap:6,marginBottom:8 }}>
                  {[{l:"注文管理",p:"orders",i:"🛒"},{l:"会員管理",p:"members",i:"👤"},
                    {l:"入金消し込み",p:"deposits",i:"💰"},{l:"書籍管理",p:"books",i:"📚"},
                    {l:"ダッシュボード",p:"dashboard",i:"📊"}].map(function(it,idx2){
                    return <button key={idx2} onClick={function(){ navigateTo(it.p); setSearchOpen(false); }}
                      style={{ padding:"6px 12px",borderRadius:6,fontSize:12,cursor:"pointer",fontFamily:"inherit",
                        background:darkMode?T_DARK.rule:T_LIGHT.bg,border:"1px solid "+(darkMode?T_DARK.rule2:T_LIGHT.rule),
                        color:darkMode?T_DARK.ink:T_LIGHT.ink }}>{it.i} {it.l}</button>;
                  })}
                </div>
                <div style={{ fontSize:10,color:darkMode?T_DARK.ink4:T_LIGHT.ink4 }}>⌨ Alt+D ダッシュボード　Alt+O 注文管理　Alt+M 会員</div>
              </div>
            )}
          </div>
        </div>
      )}

      <Toast msg={toast} onUndo={undoState ? execUndo : null} />

      {/* ── クイックアクションFAB ── */}
      <QuickActionFab navigateTo={navigateTo} setSearchOpen={setSearchOpen} setSearchQ={setSearchQ} isMobile={isMobile} darkMode={darkMode} qaConfig={qaConfig} />

      {/* ── 初回操作ガイド ── */}
      <TourGuide />

      {/* ── フィードバックフローティングボタン ── */}
      <div style={{ position:"fixed", bottom:28, right:96, zIndex:1200 }}>
        {fbOpen && (
          <div style={{ position:"absolute", bottom:"calc(100% + 12px)", right:0,
            width:360, background:T.white, borderRadius:14,
            border:"1.5px solid rgba(0,105,92,.25)",
            boxShadow:"0 8px 32px rgba(0,0,0,.18)", overflow:"hidden",
            animation:"slideIn .2s ease" }}>
            {/* ヘッダ */}
            <div style={{ padding:"14px 18px",
              background:"linear-gradient(135deg,rgba(0,105,92,.9),rgba(15,51,32,.85))",
              display:"flex",justifyContent:"space-between",alignItems:"center" }}>
              <div>
                <div style={{ fontSize:14,fontWeight:800,color:"#fff" }}>💬 フィードバックを送る</div>
                <div style={{ fontSize:11,color:"rgba(255,255,255,.7)",marginTop:1 }}>
                  📍 現在の画面：{page}
                </div>
              </div>
              <button onClick={()=>setFbOpen(false)}
                style={{ background:"rgba(255,255,255,.2)",border:"none",
                  borderRadius:6,padding:"4px 10px",cursor:"pointer",
                  color:"#fff",fontSize:12,fontWeight:700 }} aria-label="閉じる">✕</button>
            </div>

            <div style={{ padding:"16px 18px" }}>
              {/* ワンタップ絵文字 */}
              <div style={{ marginBottom:14 }}>
                <div style={{ fontSize:11,fontWeight:700,color:T.ink3,marginBottom:8 }}>
                  この画面の使い心地は？（1タップで送信）
                </div>
                <div style={{ display:"flex",gap:8,justifyContent:"center" }}>
                  {[
                    { emoji:"👍", label:"良い",    color:T.ok   },
                    { emoji:"😐", label:"普通",    color:T.ink3 },
                    { emoji:"👎", label:"困った",  color:T.red  },
                  ].map((e,i)=>(
                    <button key={i} onClick={()=>submitEmojiReaction(e.emoji)}
                      style={{ flex:1,padding:"10px 0",borderRadius:8,fontSize:24,
                        border:`2px solid ${fbEmoji===e.emoji?e.color:T.rule}`,
                        background:fbEmoji===e.emoji?e.color+"18":T.bg,
                        cursor:"pointer",textAlign:"center" }}>
                      <div>{e.emoji}</div>
                      <div style={{ fontSize:10,color:e.color,fontWeight:700,marginTop:2 }}>{e.label}</div>
                    </button>
                  ))}
                </div>
              </div>

              <div style={{ borderTop:`1px solid ${T.rule}`,paddingTop:14,marginBottom:12 }}>
                <div style={{ fontSize:11,fontWeight:700,color:T.ink3,marginBottom:8 }}>
                  詳しく報告する
                </div>
                {/* 種別 */}
                <div style={{ display:"flex",gap:6,marginBottom:10,flexWrap:"wrap" }}>
                  {Object.entries(FB_TYPE_META).map(([k,v])=>(
                    <button key={k} onClick={()=>setFbType(k)}
                      style={{ padding:"4px 10px",borderRadius:6,fontSize:11,fontWeight:700,
                        border:`1.5px solid ${fbType===k?v.color:T.rule}`,
                        background:fbType===k?v.bg:T.white,color:fbType===k?v.color:T.ink4,
                        cursor:"pointer" }}>
                      {v.icon} {v.label}
                    </button>
                  ))}
                </div>
                {/* 優先度 */}
                <div style={{ display:"flex",gap:6,marginBottom:10,flexWrap:"wrap" }}>
                  {Object.entries(FB_PRIORITY_META).map(([k,v])=>(
                    <button key={k} onClick={()=>setFbPriority(k)}
                      style={{ padding:"4px 10px",borderRadius:6,fontSize:10,fontWeight:700,
                        border:`1.5px solid ${fbPriority===k?v.color:T.rule}`,
                        background:fbPriority===k?v.color+"18":T.white,
                        color:fbPriority===k?v.color:T.ink4,cursor:"pointer" }}>
                      {v.label}
                    </button>
                  ))}
                </div>
                {/* テキスト */}
                <textarea aria-label="フィードバック内容" value={fbContent} onChange={e=>setFbContent(e.target.value)}
                  placeholder={"具体的な内容を書いてください…\n例：注文一覧の印刷ボタンを押すと確認画面が2回出る"}
                  style={{ width:"100%",height:90,padding:"8px 10px",borderRadius:7,
                    border:`1.5px solid ${T.rule}`,fontSize:12,fontFamily:"inherit",
                    outline:"none",resize:"none",boxSizing:"border-box",marginBottom:10 }} />
                <div style={{ display:"flex",gap:8,justifyContent:"flex-end" }}>
                  <button onClick={()=>setFbOpen(false)}
                    style={{ padding:"6px 14px",borderRadius:6,fontSize:12,
                      background:T.bg,border:`1px solid ${T.rule}`,cursor:"pointer",color:T.ink4 }}>
                    キャンセル
                  </button>
                  <button onClick={submitFeedback}
                    style={{ padding:"6px 16px",borderRadius:6,fontSize:12,fontWeight:700,
                      background:T.g2,border:"none",cursor:"pointer",color:"#fff" }}>
                    📨 送信
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* フィードバックボタン本体 */}
        <button onClick={()=>setFbOpen(!fbOpen)} style={{
          width:54,height:54,borderRadius:"50%",
          background:fbOpen?"linear-gradient(135deg,#00695c,"+T.g1+")":"linear-gradient(135deg,#00695c,"+T.g3+")",
          border:"none",cursor:"pointer",color:"#fff",
          fontSize:22,boxShadow:"0 4px 16px rgba(0,105,92,.45)",
          display:"flex",alignItems:"center",justifyContent:"center",
          transition:"transform .15s, box-shadow .15s",
          transform:fbOpen?"scale(1.1)":"scale(1)"
        }}
        onMouseEnter={e=>e.currentTarget.style.boxShadow="0 6px 22px rgba(0,105,92,.6)"}
        onMouseLeave={e=>e.currentTarget.style.boxShadow="0 4px 16px rgba(0,105,92,.45)"}
        title="フィードバックを送る">
          💬
        </button>
      </div>

      {/* ── 全ページ共通AIアシスタントパネル（フローティング）── */}
      {/* フローティングボタン */}
      <div style={{ position:"fixed", bottom:28, right:28, zIndex:1200 }}>
        {aiOpen && (
          <div style={{
            position:"absolute", bottom:"calc(100% + 12px)", right:0,
            width:340, background:T.white,
            borderRadius:14, border:`1.5px solid rgba(106,27,154,.25)`,
            boxShadow:"0 8px 32px rgba(0,0,0,.18)",
            overflow:"hidden",
            animation:"slideIn .2s ease"
          }}>
            {/* ドロワーヘッダー */}
            <div style={{
              padding:"14px 18px",
              background:"linear-gradient(135deg,rgba(106,27,154,.92),rgba(26,92,56,.85))",
              display:"flex", justifyContent:"space-between", alignItems:"center"
            }}>
              <div>
                <div style={{ fontSize:14, fontWeight:800, color:"#fff" }}>🤖 AIアシスタント</div>
                <div style={{ fontSize:11, color:"rgba(255,255,255,.7)", marginTop:1 }}>
                  {page === "dashboard" ? "ダッシュボード" :
                   page === "books" ? "書籍管理" :
                   page === "sales" ? "売上管理" :
                   page === "members" ? "会員管理" :
                   page === "inventory" ? "在庫管理" :
                   page === "orders" ? "注文管理" :
                   page === "bpo" ? "BPO管理" :
                   page === "pub_report" ? "出版社レポート" :
                   page === "reports" ? "レポート" :
                   page} のインサイント
                </div>
              </div>
              <button onClick={()=>setAiOpen(false)}
                style={{ background:"rgba(255,255,255,.2)", border:"none",
                  borderRadius:6, padding:"4px 10px", cursor:"pointer",
                  color:"#fff", fontSize:12, fontWeight:700 }} aria-label="閉じる">✕</button>
            </div>
            {/* インサイント本文 */}
            <div style={{ padding:"14px 16px", maxHeight:360, overflowY:"auto",
              display:"flex", flexDirection:"column", gap:10 }}>
              {(AI_PAGE_INSIGHTS[page] || AI_DEFAULT_INSIGHT).map((ins, i) => {
                const styles = {
                  summary:  { icon:"📋", color:T.navy,   bg:T.navyPale,   label:"概要" },
                  positive: { icon:"✅", color:T.ok,     bg:T.okPale,     label:"好材料" },
                  warning:  { icon:"⚠", color:T.amber,  bg:T.amberPale,  label:"注意点" },
                  action:   { icon:"💡", color:T.purple,  bg:T.purplePale, label:"改善提案" },
                  risk:     { icon:"🔴", color:T.red,    bg:T.redPale,    label:"リスク" },
                };
                const s = styles[ins.type] || styles.summary;
                return (
                  <div key={i} style={{ display:"flex", gap:9, padding:"10px 12px",
                    borderRadius:8, background:s.bg, border:`1px solid ${s.color}20` }}>
                    <span style={{ fontSize:15, flexShrink:0 }}>{s.icon}</span>
                    <div>
                      <div style={{ fontSize:11, fontWeight:800, color:s.color,
                        letterSpacing:".06em", marginBottom:2 }}>{s.label}</div>
                      <div style={{ fontSize:12, color:T.ink2, lineHeight:1.75 }}>{ins.text}</div>
                    </div>
                  </div>
                );
              })}
            </div>
            {/* フッター */}
            <div style={{ padding:"10px 16px", borderTop:`1px solid ${T.rule}`,
              background:T.surface, display:"flex", justifyContent:"space-between",
              alignItems:"center" }}>
              <span style={{ fontSize:11, color:T.ink4 }}>ページ切替で自動更新</span>
              <button onClick={()=>showToast("AIレポート生成機能は開発中です")}
                style={{ fontSize:11, padding:"5px 12px", borderRadius:5,
                  background:T.g2, color:"#fff", border:"none", cursor:"pointer",
                  fontWeight:700 }}>詳細分析を生成</button>
            </div>
          </div>
        )}

        {/* ボタン本体 */}
        <button onClick={()=>setAiOpen(!aiOpen)} style={{
          width:54, height:54, borderRadius:"50%",
          background:`linear-gradient(135deg,${T.purple},${T.g2})`,
          border:"none", cursor:"pointer", color:"#fff",
          fontSize:22, boxShadow:"0 4px 16px rgba(106,27,154,.45)",
          display:"flex", alignItems:"center", justifyContent:"center",
          transition:"transform .15s, box-shadow .15s",
          transform:aiOpen?"scale(1.1)":"scale(1)"
        }}
        onMouseEnter={e=>e.currentTarget.style.boxShadow="0 6px 22px rgba(106,27,154,.6)"}
        onMouseLeave={e=>e.currentTarget.style.boxShadow="0 4px 16px rgba(106,27,154,.45)"}
        title="AIアシスタント">
          🤖
        </button>
      </div>

      <Toast msg={toast} onUndo={undoState ? execUndo : null} />
    </>
  );
}


// ★v22.60: GitHub Pages用レンダリング
const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(React.createElement(AdminApp));
